const fs = require('fs');
const path = require('path');

function walk(dir) {
  let results = [];
  const list = fs.readdirSync(dir);
  list.forEach((file) => {
    file = path.join(dir, file);
    const stat = fs.statSync(file);
    if (stat && stat.isDirectory()) {
      results = results.concat(walk(file));
    } else {
      results.push(file);
    }
  });
  return results;
}

const files = walk('./src').filter(f => f.endsWith('.ts') || f.endsWith('.tsx'));
let fixedFiles = 0;

files.forEach(f => {
  const orig = fs.readFileSync(f, 'utf8');
  let content = orig;

  // Replace `catch (e: any)` -> `catch (e: unknown) { const error = e as Error;`
  content = content.replace(/catch\s*\((e|err):\s*any\)\s*\{/g, 'catch ($1: unknown) {\n      const error = $1 as Error;');
  // Replace `e.message` -> `error.message` ONLY if inside the catch block where we defined `error`.
  // A simpler global replace for `e.message` is fine since `e.message` outside catch is very rare, but to be safer:
  content = content.replace(/(\be\b|\berr\b)\.message/g, 'error.message');

  // Replace `(session?.user as any)` -> `(session?.user as { id?: number, email?: string })`
  content = content.replace(/\(session\?\.user\s+as\s+any\)/g, '(session?.user as { id?: number, email?: string })');

  if (orig !== content) {
    fs.writeFileSync(f, content, 'utf8');
    fixedFiles++;
  }
});

console.log(`Fixed any in ${fixedFiles} files.`);

const fs = require('fs');
const path = require('path');

function walk(dir) {
  let results = [];
  const list = fs.readdirSync(dir);
  list.forEach((file) => {
    file = path.join(dir, file);
    const stat = fs.statSync(file);
    if (stat && stat.isDirectory()) {
      results = results.concat(walk(file));
    } else {
      results.push(file);
    }
  });
  return results;
}

const files = walk('./src').filter(f => f.endsWith('.ts') || f.endsWith('.tsx'));
let fixedFiles = 0;

files.forEach(f => {
  const orig = fs.readFileSync(f, 'utf8');
  let content = orig.replace(/\(session\?\.user\s+as\s+\{\s*id\?:\s*number,\s*email\?:\s*string\s*\}\)/g, '(session?.user as { id?: number, email?: string, name?: string, accessToken?: string })');

  // also fix Object is possibly undefined in dashboard/page.tsx line 168:
  // session?.user?.id.toString() 
  content = content.replace(/\(session\?\.user\s+as\s+any\)\?.id\.toString\(\)/g, "((session?.user as { id?: number })?.id?.toString() || '')");
  content = content.replace(/\(session\?\.user\s+as\s+\{\s*id\?:\s*number,\s*email\?:\s*string,\s*name\?:\s*string,\s*accessToken\?:\s*string\s*\}\)\.id\.toString\(\)/g, "((session?.user as { id?: number })?.id?.toString() || '')");

  // fix TS2532: Object is possibly undefined `(session?.user as ...).id`
  content = content.replace(/\(session\?\.user\s+as\s+[^)]+\)\.id/g, '((session?.user as { id?: number })?.id)');

  if (orig !== content) {
    fs.writeFileSync(f, content, 'utf8');
    fixedFiles++;
  }
});

console.log(`Re-fixed session in ${fixedFiles} files.`);

