const fs = require('fs');
const results = JSON.parse(fs.readFileSync('lint_results.json', 'utf8'));
let out = '';
let totalErr = 0;
results.forEach(f => {
  const errors = f.messages.filter(m => m.severity === 2);
  if (errors.length > 0) {
    const ruleCounts = {};
    errors.forEach(e => { ruleCounts[e.ruleId] = (ruleCounts[e.ruleId] || 0) + 1; });
    out += `\n📄 ${f.filePath} (${errors.length} errors)\nRules: ${Object.entries(ruleCounts).map(([k,v])=>`${k}(${v})`).join(', ')}\n`;
    totalErr += errors.length;
  }
});
out += `\nTotal Errors: ${totalErr}\n`;
fs.writeFileSync('lint_summary_utf8.txt', out, 'utf8');
console.log('Done!');

