"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useAdminGuard } from "@/hooks/useAdminGuard";

const BACKEND = process.env.NEXT_PUBLIC_API_URL || "https://tulasiai.up.railway.app";
const FRONTEND = typeof window !== "undefined" ? window.location.origin : "";

const BACKEND_ENDPOINTS = [
  { method: "GET",  path: "/api/health",             group: "Core",          label: "Health Check" },
  { method: "GET",  path: "/api/hackathons",         group: "Hackathons",    label: "List Hackathons" },
  { method: "GET",  path: "/api/hackathons/1",       group: "Hackathons",    label: "Get Hackathon #1" },
  { method: "GET",  path: "/api/study/rooms",        group: "Study Rooms",   label: "List Rooms" },
  { method: "GET",  path: "/api/code/problems",      group: "Code Practice", label: "List Problems" },
  { method: "GET",  path: "/api/code/problems/ARR-001", group: "Code Practice", label: "Get Problem" },
  { method: "POST", path: "/api/interview/start",    group: "Interview",     label: "Start Interview",  body: { role: "Software Engineer" } },
  { method: "POST", path: "/api/startup/generate",   group: "Startup Lab",   label: "Generate Idea",    body: { domain: "EdTech", target_audience: "Students" } },
  { method: "GET",  path: "/api/certificates/my",    group: "Certificates",  label: "My Certs",         auth: true },
  { method: "GET",  path: "/api/startup/ideas",      group: "Startup Lab",   label: "Saved Ideas",      auth: true },
  { method: "GET",  path: "/api/activity/stats",     group: "Activity",      label: "Activity Stats",   auth: true },
  { method: "GET",  path: "/api/roadmaps",           group: "Roadmaps",      label: "Roadmaps",         auth: true },
];

const FRONTEND_ENDPOINTS = [
  { method: "GET",  path: "/api/auth/session",     group: "Auth",    label: "Auth Session" },
  { method: "GET",  path: "/api/auth/providers",   group: "Auth",    label: "OAuth Providers" },
  { method: "GET",  path: "/api/auth/csrf",        group: "Auth",    label: "CSRF Token" },
  { method: "GET",  path: "/dashboard",            group: "Pages",   label: "Dashboard UI" },
  { method: "GET",  path: "/dashboard/hackathons", group: "Pages",   label: "Hackathons Page" },
  { method: "GET",  path: "/dashboard/study-rooms",group: "Pages",   label: "Study Rooms Page" },
  { method: "GET",  path: "/dashboard/interview",  group: "Pages",   label: "Interview Page" },
  { method: "GET",  path: "/dashboard/startup-lab",group: "Pages",   label: "Startup Lab Page" },
  { method: "GET",  path: "/dashboard/certificates",group:"Pages",   label: "Certificates Page" },
  { method: "GET",  path: "/dashboard/code",       group: "Pages",   label: "Code Practice Page" },
];

const METHOD_COLOR: Record<string, string> = {
  GET: "#43E97B", POST: "#6C63FF", DELETE: "#FF6B6B", PUT: "#FFD93D"
};

type Status = "idle" | "loading" | "ok" | "error";
type TestResult = { status: Status; ms?: number; code?: number };

function StatusBadge({ st }: { st: TestResult | undefined }) {
  if (!st || st.status === "idle") return null;
  if (st.status === "loading") return <div style={{ width: 14, height: 14, border: "2px solid rgba(255,255,255,0.2)", borderTopColor: "white", borderRadius: "50%", animation: "spin 0.8s linear infinite" }} />;
  if (st.status === "ok") return <span style={{ color: "#43E97B", fontWeight: 700, fontSize: 12 }}>✓ {st.code} · {st.ms}ms</span>;
  return <span style={{ color: "#FF6B6B", fontWeight: 700, fontSize: 12 }}>✗ {st.code || "ERR"} · {st.ms}ms</span>;
}

export default function ApiStatusPage() {
  const { isAdmin, isLoading } = useAdminGuard();
  const [bStatuses, setBStatuses] = useState<Record<string, TestResult>>({});
  const [fStatuses, setFStatuses] = useState<Record<string, TestResult>>({});
  const [backendPing, setBackendPing] = useState<"unknown" | "alive" | "waking" | "down">("unknown");
  const [frontendPing, setFrontendPing] = useState<"unknown" | "alive" | "down">("unknown");
  const [pingMs, setPingMs] = useState<number | null>(null);
  const [tab, setTab] = useState<"backend" | "frontend" | "combined">("combined");

  useEffect(() => {
    if (isAdmin && !isLoading) {
      pingBackend(); 
      pingFrontend(); 
    }
  }, [isAdmin, isLoading]);

  const pingBackend = async () => {
    setBackendPing("waking");
    const t0 = Date.now();
    try {
      const res = await fetch(`${BACKEND}/api/health`, { signal: AbortSignal.timeout(12000) });
      const ms = Date.now() - t0;
      setPingMs(ms);
      setBackendPing(res.ok ? "alive" : "down");
    } catch { setBackendPing("down"); }
  };

  const pingFrontend = async () => {
    const t0 = Date.now();
    try {
      const res = await fetch(`${FRONTEND}/api/auth/providers`, { signal: AbortSignal.timeout(5000) });
      setFrontendPing(res.ok ? "alive" : "down");
    } catch { setFrontendPing("down"); }
  };

  useEffect(() => { pingBackend(); pingFrontend(); }, []);

  const testEndpoint = async (
    base: string,
    ep: typeof BACKEND_ENDPOINTS[0],
    setFn: React.Dispatch<React.SetStateAction<Record<string, TestResult>>>
  ) => {
    setFn(s => ({ ...s, [ep.path]: { status: "loading" } }));
    const t0 = Date.now();
    try {
      const res = await fetch(`${base}${ep.path}`, {
        method: ep.method,
        headers: { "Content-Type": "application/json" },
        body: ep.body ? JSON.stringify(ep.body) : undefined,
        signal: AbortSignal.timeout(20000),
      });
      setFn(s => ({ ...s, [ep.path]: { status: res.ok ? "ok" : "error", ms: Date.now() - t0, code: res.status } }));
    } catch {
      setFn(s => ({ ...s, [ep.path]: { status: "error", ms: Date.now() - t0 } }));
    }
  };

  const testAllBackend = async () => { for (const ep of BACKEND_ENDPOINTS) await testEndpoint(BACKEND, ep, setBStatuses); };
  const testAllFrontend = async () => { for (const ep of FRONTEND_ENDPOINTS) await testEndpoint(FRONTEND, ep, setFStatuses); };
  const testAll = async () => { testAllBackend(); testAllFrontend(); };

  const backendOk = Object.values(bStatuses).filter(s => s.status === "ok").length;
  const frontendOk = Object.values(fStatuses).filter(s => s.status === "ok").length;

  const EndpointRow = ({
    ep, base, statuses, setStatuses
  }: {
    ep: typeof BACKEND_ENDPOINTS[0];
    base: string;
    statuses: Record<string, TestResult>;
    setStatuses: React.Dispatch<React.SetStateAction<Record<string, TestResult>>>;
  }) => {
    const st = statuses[ep.path];
    return (
      <div style={{
        display: "flex", alignItems: "center", gap: 10, padding: "10px 14px",
        background: "rgba(255,255,255,0.02)",
        border: `1px solid ${st?.status === "ok" ? "rgba(67,233,123,0.25)" : st?.status === "error" ? "rgba(255,107,107,0.25)" : "rgba(255,255,255,0.07)"}`,
        borderRadius: 10,
      }}>
        <span style={{ background: `${METHOD_COLOR[ep.method]}20`, color: METHOD_COLOR[ep.method], padding: "2px 8px", borderRadius: 5, fontSize: 10, fontWeight: 800, minWidth: 40, textAlign: "center" }}>{ep.method}</span>
        <span style={{ fontSize: 11, color: "var(--text-muted)", minWidth: 80, fontWeight: 600 }}>{ep.group}</span>
        <code style={{ fontSize: 12, color: "white", flex: 1, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{ep.path}</code>
        {(ep as any).auth && <span style={{ fontSize: 9, color: "#FFD93D", border: "1px solid rgba(255,217,61,0.3)", padding: "1px 6px", borderRadius: 4 }}>AUTH</span>}
        <StatusBadge st={st} />
        <button onClick={() => testEndpoint(base, ep, setStatuses)}
          style={{ padding: "4px 12px", background: "rgba(108,99,255,0.15)", border: "1px solid rgba(108,99,255,0.3)", borderRadius: 6, color: "#6C63FF", fontWeight: 700, fontSize: 11, cursor: "pointer", whiteSpace: "nowrap" }}>
          Test
        </button>
      </div>
    );
  };

  if (isLoading || !isAdmin) {
    return (
      <div style={{ display: "flex", justifyContent: "center", alignItems: "center", minHeight: "60vh" }}>
        <div style={{ color: "var(--text-muted)" }}>Initializing Security Protocol...</div>
      </div>
    );
  }

  return (
    <div style={{ maxWidth: 950, margin: "0 auto", paddingBottom: 60 }}>
      {/* Header */}
      <div style={{ marginBottom: 28 }}>
        <h1 style={{ fontSize: 30, fontWeight: 800, marginBottom: 6 }}>
          ⚡ Combined <span style={{ background: "linear-gradient(135deg, #6C63FF, #4ECDC4)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>API Status</span>
        </h1>
        <p style={{ color: "var(--text-muted)", fontSize: 13 }}>
          Live tester for both <strong style={{ color: "#4ECDC4" }}>Vercel Frontend</strong> and <strong style={{ color: "#6C63FF" }}>Render Backend</strong> — all in one place.
        </p>
      </div>

      {/* Status cards */}
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 24 }}>
        {/* Frontend card */}
        <div style={{ padding: "16px 20px", background: "rgba(78,205,196,0.06)", border: "1px solid rgba(78,205,196,0.25)", borderRadius: 14 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
            <div style={{ fontWeight: 700, fontSize: 14, color: "#4ECDC4" }}>🌐 Vercel Frontend</div>
            <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
              <div style={{ width: 8, height: 8, borderRadius: 4, background: frontendPing === "alive" ? "#43E97B" : "#FFD93D", boxShadow: `0 0 6px ${frontendPing === "alive" ? "#43E97B" : "#FFD93D"}` }} />
              <span style={{ fontSize: 12, fontWeight: 700 }}>{frontendPing === "alive" ? "Online" : "Checking..."}</span>
            </div>
          </div>
          <div style={{ fontSize: 11, color: "var(--text-muted)", fontFamily: "monospace", marginBottom: 10, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{FRONTEND || "https://tulasi.vercel.app"}</div>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <span style={{ fontSize: 12, color: "var(--text-secondary)" }}>{frontendOk}/{FRONTEND_ENDPOINTS.length} endpoints OK</span>
            <button onClick={testAllFrontend} style={{ padding: "5px 12px", background: "rgba(78,205,196,0.15)", border: "1px solid rgba(78,205,196,0.3)", borderRadius: 8, color: "#4ECDC4", fontWeight: 700, fontSize: 11, cursor: "pointer" }}>
              Test All
            </button>
          </div>
        </div>

        {/* Backend card */}
        <div style={{ padding: "16px 20px", background: "rgba(108,99,255,0.06)", border: "1px solid rgba(108,99,255,0.25)", borderRadius: 14 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
            <div style={{ fontWeight: 700, fontSize: 14, color: "#6C63FF" }}>🔧 Render Backend</div>
            <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
              <div style={{ width: 8, height: 8, borderRadius: 4, background: backendPing === "alive" ? "#43E97B" : backendPing === "waking" ? "#FFD93D" : "#FF6B6B", boxShadow: `0 0 6px ${backendPing === "alive" ? "#43E97B" : "#FFD93D"}` }} />
              <span style={{ fontSize: 12, fontWeight: 700 }}>
                {backendPing === "alive" ? `Online · ${pingMs}ms` : backendPing === "waking" ? "Waking up..." : "Down"}
              </span>
            </div>
          </div>
          <div style={{ fontSize: 11, color: "var(--text-muted)", fontFamily: "monospace", marginBottom: 10, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{BACKEND}</div>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <span style={{ fontSize: 12, color: "var(--text-secondary)" }}>{backendOk}/{BACKEND_ENDPOINTS.length} endpoints OK</span>
            <div style={{ display: "flex", gap: 8 }}>
              <button onClick={pingBackend} style={{ padding: "5px 10px", background: "transparent", border: "1px solid rgba(108,99,255,0.3)", borderRadius: 8, color: "var(--text-muted)", fontWeight: 600, fontSize: 11, cursor: "pointer" }}>Ping</button>
              <button onClick={testAllBackend} style={{ padding: "5px 12px", background: "rgba(108,99,255,0.15)", border: "1px solid rgba(108,99,255,0.3)", borderRadius: 8, color: "#6C63FF", fontWeight: 700, fontSize: 11, cursor: "pointer" }}>Test All</button>
            </div>
          </div>
        </div>
      </div>

      {/* Tab + Test All row */}
      <div style={{ display: "flex", gap: 12, marginBottom: 20, alignItems: "center", flexWrap: "wrap" }}>
        {(["combined", "backend", "frontend"] as const).map(t => (
          <button key={t} onClick={() => setTab(t)}
            style={{ padding: "8px 18px", borderRadius: 8, fontWeight: 700, fontSize: 13, cursor: "pointer", border: `1px solid ${tab === t ? "#6C63FF" : "var(--border)"}`, background: tab === t ? "rgba(108,99,255,0.2)" : "transparent", color: tab === t ? "#6C63FF" : "var(--text-muted)" }}>
            {t === "combined" ? "🔗 Combined" : t === "backend" ? "🔧 Backend Only" : "🌐 Frontend Only"}
          </button>
        ))}
        <button onClick={testAll} style={{ marginLeft: "auto", padding: "8px 20px", background: "var(--brand-primary)", color: "white", border: "none", borderRadius: 8, fontWeight: 700, fontSize: 13, cursor: "pointer" }}>
          ▶ Test All
        </button>
      </div>

      {/* Endpoint list */}
      <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
        {(tab === "backend" || tab === "combined") && (
          <>
            {tab === "combined" && <div style={{ fontSize: 11, fontWeight: 800, textTransform: "uppercase", letterSpacing: "1px", color: "#6C63FF", marginTop: 8, marginBottom: 4 }}>🔧 Render Backend — FastAPI</div>}
            {BACKEND_ENDPOINTS.map(ep => (
              <EndpointRow key={ep.path} ep={ep} base={BACKEND} statuses={bStatuses} setStatuses={setBStatuses} />
            ))}
          </>
        )}
        {(tab === "frontend" || tab === "combined") && (
          <>
            {tab === "combined" && <div style={{ fontSize: 11, fontWeight: 800, textTransform: "uppercase", letterSpacing: "1px", color: "#4ECDC4", marginTop: 20, marginBottom: 4 }}>🌐 Vercel Frontend — Next.js</div>}
            {FRONTEND_ENDPOINTS.map(ep => (
              <EndpointRow key={ep.path} ep={ep} base={FRONTEND} statuses={fStatuses} setStatuses={setFStatuses} />
            ))}
          </>
        )}
      </div>

      <style>{`@keyframes spin { 100% { transform: rotate(360deg); } }`}</style>
    </div>
  );
}

"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import { useSession } from "next-auth/react";
import toast from "react-hot-toast";

export default function BillingPage() {
  const { data: session } = useSession();
  const [loading, setLoading] = useState(false);
  const token = typeof window !== "undefined" ? localStorage.getItem("token") || "" : "";

  const handleSubscribe = async () => {
    
    setLoading(true);
    try {
      const RENDER_BACKEND_URL = process.env.NEXT_PUBLIC_API_URL || "https://tulasiai.up.railway.app";
      const res = await fetch(`${RENDER_BACKEND_URL}/api/stripe/create-checkout-session`, {
        method: "POST",
        headers: { "Authorization": `Bearer ${token}` }
      });
      const data = await res.json();
      if (res.ok && data.checkout_url) {
        window.location.href = data.checkout_url;
      } else {
        toast.error(data.detail || "Failed to initiate checkout");
        setLoading(false);
      }
    } catch (err) {
      toast.error("Network error during checkout");
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: "40px 20px", maxWidth: 1000, margin: "0 auto" }}>
      <div style={{ textAlign: "center", marginBottom: 60 }}>
        <h1 style={{ fontSize: 32, fontWeight: 800, color: "var(--text-primary)", marginBottom: 16 }}>Upgrade to Tulasi AI Pro</h1>
        <p style={{ fontSize: 18, color: "var(--text-secondary)" }}>Supercharge your learning with unlimited AI tools.</p>
      </div>

      <div style={{ display: "flex", gap: 32, flexWrap: "wrap", justifyContent: "center" }}>
        
        {/* Free Plan */}
        <div className="glass-card" style={{ flex: 1, minWidth: 300, maxWidth: 400, padding: 40, borderTop: "4px solid var(--border)" }}>
          <h3 style={{ fontSize: 24, fontWeight: 700, color: "var(--text-primary)", marginBottom: 8 }}>Free</h3>
          <div style={{ fontSize: 40, fontWeight: 800, color: "var(--text-primary)", marginBottom: 24 }}>$0 <span style={{ fontSize: 16, color: "var(--text-muted)", fontWeight: 500 }}>/forever</span></div>
          <ul style={{ listStyle: "none", padding: 0, margin: "0 0 32px 0", color: "var(--text-secondary)", display: "flex", flexDirection: "column", gap: 12 }}>
            <li>✅ 10 AI Chats per Day</li>
            <li>✅ Basic Dashboard</li>
            <li>✅ Public Leaderboard</li>
            <li style={{ opacity: 0.4 }}>❌ No Mock Interviews</li>
            <li style={{ opacity: 0.4 }}>❌ No Resume Analyzer</li>
          </ul>
          <button disabled style={{ width: "100%", padding: 14, borderRadius: 12, background: "var(--surface-hover)", color: "var(--text-muted)", fontWeight: 600, border: "none" }}>Current Plan</button>
        </div>

        {/* Pro Plan */}
        <motion.div whileHover={{ scale: 1.02 }} className="glass-card" style={{ flex: 1, minWidth: 300, maxWidth: 400, padding: 40, borderTop: "4px solid #8B5CF6", position: "relative" }}>
          <div style={{ position: "absolute", top: -14, right: 30, background: "linear-gradient(135deg, #8B5CF6, #D946EF)", color: "white", padding: "4px 12px", borderRadius: 20, fontSize: 12, fontWeight: 700, letterSpacing: "1px" }}>MOST POPULAR</div>
          <h3 style={{ fontSize: 24, fontWeight: 700, color: "var(--text-primary)", marginBottom: 8 }}>Pro</h3>
          <div style={{ fontSize: 40, fontWeight: 800, color: "var(--text-primary)", marginBottom: 24 }}>$9.99 <span style={{ fontSize: 16, color: "var(--text-muted)", fontWeight: 500 }}>/month</span></div>
          <ul style={{ listStyle: "none", padding: 0, margin: "0 0 32px 0", color: "var(--text-secondary)", display: "flex", flexDirection: "column", gap: 12 }}>
            <li>✨ <strong>Unlimited</strong> AI Chats</li>
            <li>🚀 <strong>Unlimited</strong> Mock Interviews</li>
            <li>📄 <strong>Unlimited</strong> Deep Resume Analysis</li>
            <li>⚡ Priority GPT-4 / Gemini Access</li>
            <li>🎯 Access to Premium Hackathons</li>
          </ul>
          <button 
            onClick={handleSubscribe} 
            disabled={loading}
            style={{ width: "100%", padding: 14, borderRadius: 12, background: "linear-gradient(135deg, #8B5CF6, #D946EF)", color: "white", fontWeight: 700, border: "none", cursor: loading ? "wait" : "pointer" }}
          >
            {loading ? "Redirecting to Stripe..." : "Upgrade to Pro"}
          </button>
        </motion.div>

      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { roadmapApi } from "@/lib/api";
import { useSession } from "next-auth/react";

interface Milestone {
  id: string;
  name: string;
  duration: string;
}

interface Roadmap {
  id: string;
  title: string;
  icon: string;
  color: string;
  desc: string;
  skills: string[];
  projects: string[];
  coding: string[];
  interview_tips: string[];
  milestones: Milestone[];
}

export default function CareerRoadmapsPage() {
  const { data: session } = useSession();
  const [roadmaps, setRoadmaps] = useState<Roadmap[]>([]);
  const [completedMilestones, setCompletedMilestones] = useState<Set<string>>(new Set());
  const [activeId, setActiveId] = useState("swe");
  const [activeSection, setActiveSection] = useState("milestones");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const fetchRoadmaps = async () => {
    setLoading(true);
    try {
      const token = typeof window !== "undefined" ? localStorage.getItem("token") || "" : "";
            const data = await roadmapApi.getRoadmaps(token);
      const fetchedRoadmaps = data.roadmaps as unknown as Roadmap[];
      setRoadmaps(fetchedRoadmaps);
      setCompletedMilestones(new Set((data.completed_milestones as string[]) || []));
      if (fetchedRoadmaps && fetchedRoadmaps.length > 0) {
        if (!fetchedRoadmaps.find((r) => r.id === activeId)) {
          setActiveId(fetchedRoadmaps[0].id);
        }
      }
    } catch (err: unknown) {
      const error = err as Error;
      setError("Failed to load roadmaps. The backend might be sleeping. Please try again later.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchRoadmaps();
  }, [session]);

  const handleCompleteMilestone = async (milestoneId: string) => {
    if (completedMilestones.has(milestoneId)) return; // already completed
    
    // Optimistic UI update
    setCompletedMilestones(prev => {
      const next = new Set(prev);
      next.add(milestoneId);
      return next;
    });

    try {
      const token = typeof window !== "undefined" ? localStorage.getItem("token") || "" : "";
      await roadmapApi.logProgress(activeId, milestoneId, token);
    } catch (err) {
      // Revert optimism if failed
      setCompletedMilestones(prev => {
        const next = new Set(prev);
        next.delete(milestoneId);
        return next;
      });
      alert("Failed to track progress. Backend might be unreachable.");
    }
  };

  const active = roadmaps.find(r => r.id === activeId);

  if (loading) return <div style={{ color: "var(--text-secondary)", textAlign: "center", marginTop: 100 }}>Loading roadmaps...</div>;
  if (error || !active) {
    return (
      <div style={{ textAlign: "center", marginTop: 100 }}>
        <p style={{ color: "var(--danger)" }}>{error || "No roadmaps available."}</p>
        <button onClick={fetchRoadmaps} style={{ marginTop: 20, padding: "10px 20px", background: "var(--primary)", borderRadius: 8, border: "none", cursor: "pointer", color: "black", fontWeight: "bold" }}>Retry</button>
      </div>
    );
  }

  return (
    <div style={{ maxWidth: 1200, margin: "0 auto", paddingBottom: 60 }}>
      <div style={{ textAlign: "center", marginBottom: 40 }}>
        <h1 style={{ fontSize: 36, fontWeight: 800, fontFamily: "var(--font-outfit)", marginBottom: 12 }}>
          Career <span style={{ background: "linear-gradient(135deg, #FF6B6B, #4ECDC4)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>Roadmaps</span>
        </h1>
        <p style={{ color: "var(--text-secondary)", fontSize: 16, maxWidth: 600, margin: "0 auto" }}>
          15 step-by-step guides to mastering the skills for top tech roles. Follow at your own pace.
        </p>
      </div>

      <div style={{ display: "flex", gap: 32, alignItems: "flex-start" }}>
        {/* Sidebar Nav */}
        <div style={{ width: 220, flexShrink: 0, display: "flex", flexDirection: "column", gap: 4 }}>
          {roadmaps.map(r => (
            <button key={r.id} onClick={() => setActiveId(r.id)}
              style={{
                display: "flex", alignItems: "center", gap: 10, padding: "10px 14px",
                borderRadius: 12, border: "none", cursor: "pointer", fontSize: 13, fontWeight: 700, textAlign: "left",
                background: activeId === r.id ? `${r.color}20` : "transparent",
                color: activeId === r.id ? r.color : "var(--text-muted)",
                boxShadow: activeId === r.id ? `inset 3px 0 0 ${r.color}` : "none",
                transition: "all 0.2s ease",
              }}
            >
              <span style={{ fontSize: 18 }}>{r.icon}</span> {r.title}
            </button>
          ))}
        </div>

        {/* Main Content */}
        <AnimatePresence mode="wait">
          <motion.div key={active.id}
            initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }}
            transition={{ duration: 0.2 }}
            className="dash-card"
            style={{ flex: 1, padding: 36, background: "rgba(255,255,255,0.02)", border: `1px solid ${active.color}30` }}
          >
            <div style={{ display: "flex", alignItems: "center", gap: 16, marginBottom: 20 }}>
              <div style={{ width: 56, height: 56, borderRadius: 16, background: `${active.color}20`, border: `1px solid ${active.color}40`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 28 }}>
                {active.icon}
              </div>
              <div>
                <h2 style={{ fontSize: 28, fontWeight: 800, color: active.color, margin: 0 }}>{active.title}</h2>
                <p style={{ margin: 0, fontSize: 14, color: "var(--text-secondary)" }}>{active.desc}</p>
              </div>
            </div>

            {/* Section tabs */}
            <div style={{ display: "flex", gap: 8, marginBottom: 28, borderBottom: "1px solid rgba(255,255,255,0.08)", paddingBottom: 16 }}>
              {[
                { id: "milestones", label: "🛣️ Roadmap" },
                { id: "skills", label: "🛠️ Skills" },
                { id: "projects", label: "🚀 Projects" },
                { id: "coding", label: "💻 Coding" },
                { id: "interview", label: "🎯 Interview" },
              ].map(s => (
                <button key={s.id} onClick={() => setActiveSection(s.id)}
                  style={{
                    padding: "6px 16px", borderRadius: 20, border: "none", cursor: "pointer", fontSize: 13, fontWeight: 600,
                    background: activeSection === s.id ? active.color : "rgba(255,255,255,0.06)",
                    color: activeSection === s.id ? "black" : "var(--text-secondary)",
                    transition: "all 0.2s",
                  }}
                >{s.label}</button>
              ))}
            </div>

            <AnimatePresence mode="wait">
              <motion.div key={activeSection} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}>

                {activeSection === "milestones" && (
                  <div style={{ display: "flex", flexDirection: "column", gap: 16, borderLeft: `2px solid ${active.color}`, paddingLeft: 24, marginLeft: 8 }}>
                    {active.milestones.map((m, idx) => {
                      const isCompleted = completedMilestones.has(m.id);
                      return (
                      <div key={idx} style={{ position: "relative", cursor: "pointer", opacity: isCompleted ? 0.6 : 1, transition: "0.2s" }} onClick={() => handleCompleteMilestone(m.id)}>
                        <div style={{ position: "absolute", left: -31, top: 6, width: 12, height: 12, borderRadius: "50%", background: isCompleted ? active.color : "var(--background)", border: `2px solid ${active.color}` }} />
                        <h4 style={{ fontSize: 16, fontWeight: 700, color: "white", margin: "0 0 4px", textDecoration: isCompleted ? "line-through" : "none" }}>{m.name}</h4>
                        <span style={{ fontSize: 12, color: active.color, fontWeight: 600, background: `${active.color}15`, padding: "2px 10px", borderRadius: 6 }}>⏱ {m.duration} {isCompleted && "✓ Done"}</span>
                      </div>
                    )})}
                  </div>
                )}

                {activeSection === "skills" && (
                  <div style={{ display: "flex", flexWrap: "wrap", gap: 10 }}>
                    {active.skills.map(s => (
                      <span key={s} style={{ padding: "8px 16px", background: `${active.color}15`, border: `1px solid ${active.color}40`, borderRadius: 20, fontSize: 13, fontWeight: 600, color: "white" }}>{s}</span>
                    ))}
                  </div>
                )}

                {activeSection === "projects" && (
                  <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
                    {active.projects.map((p, i) => (
                      <div key={i} style={{ padding: "14px 18px", background: "rgba(255,255,255,0.03)", borderRadius: 12, border: "1px solid rgba(255,255,255,0.06)", display: "flex", alignItems: "center", gap: 12 }}>
                        <span style={{ color: active.color, fontSize: 18 }}>🚀</span>
                        <span style={{ fontSize: 15, fontWeight: 600 }}>{p}</span>
                      </div>
                    ))}
                  </div>
                )}

                {activeSection === "coding" && (
                  <div style={{ display: "flex", flexWrap: "wrap", gap: 10 }}>
                    {active.coding.map(c => (
                      <span key={c} style={{ padding: "8px 16px", background: "rgba(108,99,255,0.1)", border: "1px solid rgba(108,99,255,0.2)", borderRadius: 20, fontSize: 13, fontWeight: 600, color: "#9B95FF" }}>💻 {c}</span>
                    ))}
                  </div>
                )}

                {activeSection === "interview" && (
                  <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
                    {active.interview_tips.map((tip, i) => (
                      <div key={i} style={{ padding: "12px 16px", background: "rgba(255,215,0,0.06)", borderRadius: 10, border: "1px solid rgba(255,215,0,0.15)", display: "flex", gap: 10, alignItems: "flex-start" }}>
                        <span style={{ color: "#FFD700" }}>⭐</span>
                        <span style={{ fontSize: 14, color: "rgba(255,255,255,0.9)" }}>{tip}</span>
                      </div>
                    ))}
                    <a href="/dashboard/interview" style={{ textDecoration: "none", marginTop: 8 }}>
                      <button style={{ width: "100%", padding: "12px", borderRadius: 12, background: `linear-gradient(135deg, ${active.color}, #6C63FF)`, border: "none", color: "white", fontWeight: 700, fontSize: 15, cursor: "pointer" }}>
                        🎯 Start Mock Interview →
                      </button>
                    </a>
                  </div>
                )}

              </motion.div>
            </AnimatePresence>
          </motion.div>
        </AnimatePresence>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { motion } from "framer-motion";
import { useSession } from "next-auth/react";
import { certificateApi } from "@/lib/api";

interface Milestone {
  id: string; title: string; desc: string; icon: string; category: string;
  current_pct: number; can_generate: boolean; already_earned: boolean;
}

interface Certificate {
  id: number; title: string; issuer: string; type: string; issued_at: string;
}

export default function CertificatesPage() {
  const { data: session } = useSession();
  const [certificates, setCertificates] = useState<Certificate[]>([]);
  const [milestones, setMilestones] = useState<Milestone[]>([]);
  const [loading, setLoading] = useState(true);
  const [generating, setGenerating] = useState<string | null>(null);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");


  const fetchCertificates = async () => {
    setLoading(true);
    try {
      const token = typeof window !== "undefined" ? localStorage.getItem("token") || "" : "";
      
      const data = await certificateApi.list(token);
      setCertificates((data.certificates as unknown as Certificate[]) || []);
      setMilestones((data.milestones as unknown as Milestone[]) || []);
    } catch (e) {
      setError("Could not load certificates. The backend might be sleeping (takes ~50s to wake up). Please try again.");
    } finally { setLoading(false); }
  };

  const generateCertificate = async (milestoneId: string) => {
    setGenerating(milestoneId); setError(""); setSuccess("");
    try {
      const token = typeof window !== "undefined" ? localStorage.getItem("token") || "" : "";
      const data = await certificateApi.generate(milestoneId, token);
      setSuccess(data.message || "🎉 Certificate generated!");
      fetchCertificates();
    } catch (e: unknown) {
      const error = e as Error;
      setError(error.message || "Failed to generate certificate.");
    } finally { setGenerating(null); }
  };

  useEffect(() => { 
    if (session) fetchCertificates(); 
  }, [session]);

  const formatDate = (iso: string) => new Date(iso).toLocaleDateString("en-IN", { day: "numeric", month: "long", year: "numeric" });

  const CATEGORY_COLOR: Record<string, string> = {
    coding: "#4ECDC4", interview: "#FFD93D", roadmap: "#43E97B", videos: "#6C63FF",
  };

  return (
    <div style={{ maxWidth: 1000, margin: "0 auto", paddingBottom: 60 }}>
      <div style={{ marginBottom: 36 }}>
        <h1 style={{ fontSize: 32, fontWeight: 800, fontFamily: "Outfit", marginBottom: 10 }}>
          🎓 Certificates
        </h1>
        <p style={{ color: "var(--text-secondary)", fontSize: 15, maxWidth: 600 }}>
          Certificates are earned — not handed out. Complete 100% of a program to unlock yours.
        </p>
      </div>

      {error && (
        <div style={{ background: "rgba(255,107,107,0.1)", border: "1px solid rgba(255,107,107,0.3)", borderRadius: 12, padding: "14px 18px", color: "#FF6B6B", marginBottom: 24, fontSize: 14 }}>
          ⚠️ {error}
        </div>
      )}
      {success && (
        <motion.div initial={{ opacity: 0, y: -10 }} animate={{ opacity: 1, y: 0 }}
          style={{ background: "rgba(67,233,123,0.1)", border: "1px solid rgba(67,233,123,0.3)", borderRadius: 12, padding: "14px 18px", color: "#43E97B", marginBottom: 24, fontSize: 14 }}>
          ✅ {success}
        </motion.div>
      )}

      {/* Earned Certificates */}
      {!loading && certificates.length > 0 && (
        <div style={{ marginBottom: 48 }}>
          <h2 style={{ fontSize: 18, fontWeight: 700, marginBottom: 20 }}>🏆 Your Earned Certificates ({certificates.length})</h2>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))", gap: 20 }}>
            {certificates.map((cert, i) => (
              <motion.div key={cert.id} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.08 }}
                style={{
                  background: "linear-gradient(135deg, rgba(255,215,0,0.08), rgba(255,140,0,0.05))",
                  border: "1px solid rgba(255,215,0,0.3)", borderRadius: 18, padding: 24,
                  position: "relative", overflow: "hidden",
                }}>
                <div style={{ position: "absolute", top: -20, right: -20, fontSize: 80, opacity: 0.06 }}>🎓</div>

                <div style={{ fontSize: 32, marginBottom: 12 }}>🏅</div>
                <div style={{ fontSize: 16, fontWeight: 800, color: "white", marginBottom: 6 }}>{cert.title}</div>
                <div style={{ fontSize: 13, color: "#FFD700", fontWeight: 600, marginBottom: 12 }}>{cert.issuer}</div>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                  <span style={{ fontSize: 11, color: "var(--text-muted)" }}>Issued {formatDate(cert.issued_at)}</span>
                  <span style={{ background: "rgba(255,215,0,0.15)", color: "#FFD700", padding: "2px 10px", borderRadius: 8, fontSize: 11, fontWeight: 700 }}>✓ Verified</span>
                </div>
              </motion.div>
            ))}
          </div>
        </div>
      )}

      {/* Milestones */}
      <div>
        <h2 style={{ fontSize: 18, fontWeight: 700, marginBottom: 8 }}>🎯 Progress Milestones</h2>
        <p style={{ color: "var(--text-secondary)", fontSize: 13, marginBottom: 24 }}>
          Reach 100% to unlock a certificate. Certificates are <strong>strictly progress-gated</strong> — no shortcuts.
        </p>

        {loading ? (
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: 20 }}>
            {[1, 2, 3, 4].map(k => (
              <div key={k} style={{ height: 180, background: "rgba(255,255,255,0.03)", borderRadius: 16, border: "1px solid rgba(255,255,255,0.05)" }} />
            ))}
          </div>
        ) : (
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: 20 }}>
            {milestones.map((m, i) => {
              const color = CATEGORY_COLOR[m.category] || "#6C63FF";
              const locked = !m.can_generate;
              const earned = m.already_earned;
              return (
                <motion.div key={m.id} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.1 }}
                  className="dash-card"
                  style={{
                    padding: 24,
                    background: earned ? "rgba(255,215,0,0.05)" : locked ? "rgba(255,255,255,0.02)" : "rgba(78,205,196,0.06)",
                    border: earned ? "1px solid rgba(255,215,0,0.3)" : locked ? "1px solid rgba(255,255,255,0.06)" : `1px solid ${color}50`,
                  }}
                >
                  <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 14 }}>
                    <span style={{ fontSize: 32 }}>{earned ? "🏅" : locked ? "🔒" : "🔓"} {m.icon}</span>
                    <span style={{ fontSize: 11, fontWeight: 700, padding: "3px 10px", borderRadius: 8,
                      background: earned ? "rgba(255,215,0,0.15)" : locked ? "rgba(255,255,255,0.05)" : `${color}20`,
                      color: earned ? "#FFD700" : locked ? "var(--text-muted)" : color }}>
                      {earned ? "✓ EARNED" : `${m.current_pct}%`}
                    </span>
                  </div>
                  <h3 style={{ fontSize: 15, fontWeight: 800, color: earned ? "#FFD700" : "white", marginBottom: 6 }}>{m.title}</h3>
                  <p style={{ fontSize: 12, color: "var(--text-secondary)", marginBottom: 16, lineHeight: 1.5 }}>{m.desc}</p>

                  {/* Progress bar */}
                  <div style={{ height: 6, background: "rgba(255,255,255,0.08)", borderRadius: 6, marginBottom: 16, overflow: "hidden" }}>
                    <motion.div
                      initial={{ width: 0 }} animate={{ width: `${m.current_pct}%` }} transition={{ duration: 1, delay: i * 0.1 + 0.3 }}
                      style={{ height: "100%", background: earned ? "#FFD700" : locked ? "rgba(255,255,255,0.2)" : `linear-gradient(90deg, ${color}, ${color}aa)`, borderRadius: 6 }}
                    />
                  </div>

                  {!earned && (
                    <motion.button
                      whileHover={m.can_generate ? { scale: 1.03 } : {}}
                      whileTap={m.can_generate ? { scale: 0.97 } : {}}
                      onClick={() => m.can_generate && generateCertificate(m.id)}
                      disabled={!m.can_generate || generating === m.id}
                      style={{
                        width: "100%", padding: "10px", borderRadius: 10, border: "none", cursor: m.can_generate ? "pointer" : "default",
                        background: m.can_generate ? `linear-gradient(135deg, ${color}, #6C63FF)` : "rgba(255,255,255,0.05)",
                        color: m.can_generate ? "white" : "var(--text-muted)", fontWeight: 700, fontSize: 14,
                        opacity: generating === m.id ? 0.7 : 1,
                      }}
                    >
                      {generating === m.id ? "Generating..." : m.can_generate ? "🎓 Generate Certificate" : `🔒 Need ${100 - m.current_pct}% more`}
                    </motion.button>
                  )}
                  {earned && (
                    <button
                      onClick={() => {
                        const html = `<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8"/>
  <title>Certificate – ${m.title}</title>
  <style>
    body { margin: 0; font-family: Georgia, serif; background: #0a0a0a; color: white; display: flex; align-items: center; justify-content: center; min-height: 100vh; }
    .cert { width: 760px; border: 6px solid #FFD700; padding: 60px; text-align: center; background: linear-gradient(135deg, #0d0d1a, #12122a); border-radius: 16px; }
    .logo-container { margin-bottom: 20px; }
    .logo-img { width: 80px; height: 80px; object-fit: contain; filter: drop-shadow(0 0 10px rgba(78,205,196,0.3)); }
    .issuer { font-size: 14px; letter-spacing: 4px; color: #FFD700; text-transform: uppercase; margin-bottom: 40px; }
    .label { font-size: 13px; color: #aaa; letter-spacing: 2px; text-transform: uppercase; margin-bottom: 8px; }
    .name { font-size: 28px; font-weight: bold; color: #FFD700; border-bottom: 1px solid #FFD70040; padding-bottom: 16px; margin-bottom: 24px; }
    .title { font-size: 38px; font-weight: bold; color: white; margin-bottom: 16px; }
    .desc { font-size: 14px; color: #ccc; line-height: 1.6; max-width: 540px; margin: 0 auto 40px; }
    .date { font-size: 13px; color: #888; }
  </style>
</head>
<body>
  <div class="cert">
    <div class="logo-container">
      <img src="https://tulasiai.up.railway.app/health" onerror="this.src='/images/logo-transparent.png'" class="logo-img" />
    </div>
    <div class="issuer">Tulasi AI Platform</div>
    <div class="label">This certifies that</div>
    <div class="name">${session?.user?.name || session?.user?.email || "Tulasi AI Student"}</div>
    <div class="label">has successfully earned</div>
    <div class="title">${m.title}</div>
    <div class="desc">${m.desc}</div>
    <div class="date">Issued by Tulasi AI Platform · ${new Date().toLocaleDateString("en-IN", { day: "numeric", month: "long", year: "numeric" })}</div>
  </div>
</body>
</html>`;
                        const blob = new Blob([html], { type: "text/html" });
                        const a = document.createElement("a");
                        a.href = URL.createObjectURL(blob);
                        a.download = `${m.title.replace(/\s+/g, "_")}_Certificate.html`;
                        a.click();
                      }}
                      style={{ width: "100%", padding: "10px", borderRadius: 10, background: "rgba(255,215,0,0.1)", border: "1px solid rgba(255,215,0,0.3)", color: "#FFD700", fontWeight: 700, cursor: "pointer" }}
                    >
                      📥 Download Certificate
                    </button>
                  )}
                </motion.div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect, useRef, useCallback } from "react";
import { useSession } from "next-auth/react";
import { motion, AnimatePresence } from "framer-motion";
import { chatApi, ChatMsg } from "@/lib/api";
import { Bot, Send, Trash2, RotateCcw, Sparkles } from "lucide-react";
import toast from "react-hot-toast";

const GREETING = "Hello! I'm Tulasi AI, your personal learning companion. Ask me anything — coding concepts, career advice, interview prep, or system design.";

function TypingDots() {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 5, padding: "16px 20px" }}>
      {[0, 1, 2].map((i) => (
        <motion.div
          key={i}
          style={{ width: 7, height: 7, borderRadius: "50%", background: "var(--text-muted)" }}
          animate={{ scale: [1, 1.4, 1], opacity: [0.5, 1, 0.5] }}
          transition={{ duration: 1.2, repeat: Infinity, delay: i * 0.2, ease: "easeInOut" }}
        />
      ))}
    </div>
  );
}

function MessageBubble({ msg, index }: { msg: ChatMsg; index: number }) {
  const isUser = msg.role === "user";
  return (
    <motion.div
      initial={{ opacity: 0, y: 12 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.35, delay: index * 0.04, ease: [0.16, 1, 0.3, 1] }}
      style={{
        display: "flex",
        gap: 12,
        flexDirection: isUser ? "row-reverse" : "row",
        alignItems: "flex-end",
      }}
    >
      {/* Avatar */}
      <div style={{
        width: 34, height: 34, borderRadius: 10, flexShrink: 0,
        background: isUser ? "rgba(255,255,255,0.08)" : "var(--gradient-primary)",
        display: "flex", alignItems: "center", justifyContent: "center",
        fontSize: 13, fontWeight: 700, color: "white",
        boxShadow: isUser ? "none" : "0 0 16px rgba(124,58,237,0.3)",
      }}>
        {isUser ? "U" : <Bot size={18} />}
      </div>

      {/* Bubble */}
      <div style={{
        maxWidth: "75%",
        padding: "14px 18px",
        borderRadius: isUser ? "18px 18px 4px 18px" : "18px 18px 18px 4px",
        background: isUser
          ? "linear-gradient(135deg, #007AFF, #0056D6)"
          : "rgba(255,255,255,0.05)",
        border: isUser ? "none" : "1px solid rgba(255,255,255,0.07)",
        color: "var(--text-primary)",
        fontSize: 14.5,
        lineHeight: 1.7,
        boxShadow: isUser
          ? "0 4px 18px rgba(0,122,255,0.25)"
          : "0 2px 8px rgba(0,0,0,0.15)",
        whiteSpace: "pre-wrap",
        wordBreak: "break-word",
      }}>
        {msg.content}
      </div>
    </motion.div>
  );
}

export default function ChatPage() {
  const { data: session } = useSession();
  const [messages, setMessages] = useState<ChatMsg[]>([
    { role: "assistant", content: GREETING },
  ]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [sessionId, setSessionId] = useState<string>("");
  const [mounted, setMounted] = useState(false);
  const endRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => { setMounted(true); }, []);

  // Auto-scroll on new messages
  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, loading]);

  // Auto-resize textarea
  useEffect(() => {
    if (inputRef.current) {
      inputRef.current.style.height = "auto";
      inputRef.current.style.height = Math.min(inputRef.current.scrollHeight, 160) + "px";
    }
  }, [input]);

  const getToken = useCallback((): string | null => {
    if (typeof window === "undefined") return null;
    return localStorage.getItem("token");
  }, []);

  const hasToken = mounted && !!getToken();

  const handleSend = async () => {
    const token = getToken();
    const text = input.trim();

    if (!text || loading) return;
    if (!token) {
      toast.error("Please log in to use the AI chat.");
      return;
    }

    setMessages((prev) => [...prev, { role: "user", content: text }]);
    setInput("");
    setLoading(true);

    try {
      const res = await chatApi.send(text, sessionId || undefined, token);
      if (res.session_id && !sessionId) setSessionId(res.session_id);
      setMessages((prev) => [
        ...prev,
        { role: "assistant", content: res.response || "No response received." },
      ]);
    } catch (err: unknown) {
      const error = err as Error;
      const errMsg = error.message || "Failed to connect to backend.";
      toast.error(errMsg.length > 80 ? "Connection failed. Please try again." : errMsg);
      setMessages((prev) => [
        ...prev,
        {
          role: "assistant",
          content: "I'm having trouble connecting right now. Please try again in a moment.",
        },
      ]);
    } finally {
      setLoading(false);
      inputRef.current?.focus();
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const clearChat = () => {
    setMessages([{ role: "assistant", content: GREETING }]);
    setSessionId("");
  };

  if (!mounted) return null;

  return (
    <div style={{ display: "flex", flexDirection: "column", height: "calc(100vh - 120px)", maxWidth: 900, margin: "0 auto", width: "100%" }}>

      {/* Header */}
      <motion.div
        initial={{ opacity: 0, y: -10 }}
        animate={{ opacity: 1, y: 0 }}
        style={{
          display: "flex", alignItems: "center", justifyContent: "space-between",
          padding: "0 0 20px",
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
          <div style={{
            width: 44, height: 44, borderRadius: 14,
            background: "var(--gradient-primary)",
            display: "flex", alignItems: "center", justifyContent: "center",
            boxShadow: "0 0 20px rgba(124,58,237,0.35)",
          }}>
            <Bot size={22} color="white" />
          </div>
          <div>
            <h1 style={{ fontSize: 20, fontWeight: 800, margin: 0, letterSpacing: "-0.5px" }}>
              Tulasi AI Chat
            </h1>
            <p style={{ fontSize: 12, color: "var(--text-muted)", margin: 0 }}>
              Powered by Gemini — always learning with you
            </p>
          </div>
        </div>

        <div style={{ display: "flex", gap: 8 }}>
          <motion.button
            whileHover={{ scale: 1.04 }}
            whileTap={{ scale: 0.96 }}
            onClick={clearChat}
            title="Clear chat"
            style={{
              display: "flex", alignItems: "center", gap: 6,
              padding: "8px 14px", borderRadius: 10,
              background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.07)",
              color: "var(--text-secondary)", cursor: "pointer", fontSize: 13, fontWeight: 500,
            }}
          >
            <Trash2 size={14} /> Clear
          </motion.button>
        </div>
      </motion.div>

      {/* Chat window */}
      <div style={{
        flex: 1, overflowY: "auto", display: "flex", flexDirection: "column",
        gap: 20, padding: "24px",
        background: "rgba(255,255,255,0.015)",
        borderRadius: 20,
        border: "1px solid rgba(255,255,255,0.06)",
        boxShadow: "0 4px 24px rgba(0,0,0,0.2)",
        marginBottom: 16,
        scrollbarWidth: "thin",
        scrollbarColor: "rgba(255,255,255,0.08) transparent",
      }}>
        <AnimatePresence>
          {messages.map((msg, i) => (
            <MessageBubble key={i} msg={msg} index={i} />
          ))}
        </AnimatePresence>

        {loading && (
          <motion.div
            initial={{ opacity: 0, y: 8 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0 }}
            style={{
              display: "flex", gap: 12, alignItems: "flex-end",
            }}
          >
            <div style={{
              width: 34, height: 34, borderRadius: 10, flexShrink: 0,
              background: "var(--gradient-primary)",
              display: "flex", alignItems: "center", justifyContent: "center",
              boxShadow: "0 0 16px rgba(124,58,237,0.3)",
            }}>
              <Bot size={18} color="white" />
            </div>
            <div style={{
              background: "rgba(255,255,255,0.05)",
              border: "1px solid rgba(255,255,255,0.07)",
              borderRadius: "18px 18px 18px 4px",
            }}>
              <TypingDots />
            </div>
          </motion.div>
        )}
        <div ref={endRef} />
      </div>

      {/* Input area */}
      <motion.div
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.2 }}
        style={{
          background: "rgba(255,255,255,0.035)",
          border: `1px solid ${!hasToken ? "rgba(255,100,100,0.2)" : "rgba(255,255,255,0.08)"}`,
          borderRadius: 18, padding: "12px 16px",
          display: "flex", gap: 12, alignItems: "flex-end",
          backdropFilter: "blur(12px)",
        }}
      >
        {!hasToken && (
          <div style={{
            position: "absolute", bottom: "100%", left: 0, right: 0,
            textAlign: "center", color: "#F43F5E", fontSize: 12,
            padding: "6px", marginBottom: 4,
          }}>
            Please sign in to start chatting
          </div>
        )}

        <textarea
          ref={inputRef}
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder={hasToken ? "Ask me anything... (Enter to send, Shift+Enter for new line)" : "Please log in to chat..."}
          disabled={!hasToken || loading}
          rows={1}
          style={{
            flex: 1,
            background: "transparent",
            border: "none",
            outline: "none",
            color: "var(--text-primary)",
            fontSize: 14.5,
            fontFamily: "var(--font-inter)",
            resize: "none",
            lineHeight: 1.6,
            padding: "4px 0",
            opacity: !hasToken ? 0.5 : 1,
            minHeight: 28,
            maxHeight: 160,
          }}
        />

        <motion.button
          whileHover={{ scale: 1.08, boxShadow: "0 0 24px rgba(124,58,237,0.45)" }}
          whileTap={{ scale: 0.94 }}
          onClick={handleSend}
          disabled={!hasToken || loading || !input.trim()}
          style={{
            width: 42, height: 42, borderRadius: 13, flexShrink: 0,
            background: input.trim() && hasToken && !loading
              ? "var(--gradient-primary)"
              : "rgba(255,255,255,0.06)",
            border: "none",
            display: "flex", alignItems: "center", justifyContent: "center",
            cursor: input.trim() && hasToken && !loading ? "pointer" : "not-allowed",
            transition: "all 0.2s var(--ease-premium)",
            boxShadow: input.trim() && hasToken && !loading
              ? "0 4px 14px rgba(124,58,237,0.3)" : "none",
          }}
        >
          <Send size={17} color={input.trim() && hasToken && !loading ? "white" : "rgba(255,255,255,0.25)"} />
        </motion.button>
      </motion.div>

      <p style={{ textAlign: "center", fontSize: 11, color: "var(--text-muted)", marginTop: 8 }}>
        Tulasi AI can make mistakes. Verify important information independently.
      </p>
    </div>
  );
}

