"use client";

import { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useSession } from "next-auth/react";
import { groupApi } from "@/lib/api";

interface Group {
  id: number;
  name: string;
  description: string;
  join_code: string;
  member_count: number;
  created_at: string;
}

interface Message {
  id: number;
  user_id: number;
  user_name: string;
  content: string;
  created_at: string;
}

export default function GroupsPage() {
  const { data: session } = useSession();
  const token = typeof window !== "undefined" ? localStorage.getItem("token") || "" : "";
  const currentUserId = (session?.user as { id?: number, email?: string, name?: string, accessToken?: string })?.id;

  const [groups, setGroups] = useState<Group[]>([]);
  const [activeGroup, setActiveGroup] = useState<Group | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(true);
  const [sending, setSending] = useState(false);
  const [showModal, setShowModal] = useState<"create" | "join" | null>(null);
  const [modalInput, setModalInput] = useState({ name: "", description: "", code: "" });
  const [modalError, setModalError] = useState("");
  const [copied, setCopied] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const pollRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    if (token) fetchGroups();
  }, [token]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  useEffect(() => {
    if (activeGroup && token) {
      fetchMessages();
      pollRef.current = setInterval(fetchMessages, 3000);
    }
    return () => { if (pollRef.current) clearInterval(pollRef.current); };
  }, [activeGroup]);

  const fetchGroups = async () => {
    try {
      const data = await groupApi.list(token);
      const fetchedGroups = data.groups as unknown as Group[];
      setGroups(fetchedGroups || []);
      if (fetchedGroups?.length && !activeGroup) setActiveGroup(fetchedGroups[0]);
    } catch (e) {}
    setLoading(false);
  };

  const fetchMessages = async () => {
    if (!activeGroup ) return;
    try {
      const data = await groupApi.getMessages(activeGroup.id, token);
      setMessages((data.messages as unknown as Message[]) || []);
    } catch (e) {}
  };

  const sendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || !activeGroup  || sending) return;
    const content = input.trim();
    setInput("");
    setSending(true);
    try {
      const msg = await groupApi.sendMessage(activeGroup.id, content, token);
      setMessages(prev => [...prev, msg as unknown as Message]);
    } catch (e) {}
    setSending(false);
  };

  const handleCreate = async () => {
    if (!modalInput.name.trim() ) return;
    setModalError("");
    try {
      const newGroup = await groupApi.create(modalInput.name, modalInput.description, token) as unknown as Group;
      setGroups(prev => [...prev, { ...newGroup, member_count: 1 }]);
      setActiveGroup({ ...newGroup, member_count: 1 });
      setShowModal(null);
      setModalInput({ name: "", description: "", code: "" });
    } catch (e: unknown) {
      const error = e as Error;
      setModalError(error.message || "Failed to create group");
    }
  };

  const handleJoin = async () => {
    if (!modalInput.code.trim() ) return;
    setModalError("");
    try {
      const res = await groupApi.join(modalInput.code.trim().toUpperCase(), token);
      await fetchGroups();
      setShowModal(null);
      setModalInput({ name: "", description: "", code: "" });
    } catch (e: unknown) {
      const error = e as Error;
      setModalError(error.message || "Invalid join code");
    }
  };

  const copyCode = (code: string) => {
    navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div style={{ maxWidth: 1200, margin: "0 auto", height: "calc(100vh - 120px)", display: "flex", gap: 24 }}>

      {/* Left: Group List */}
      <div className="dash-card" style={{ width: 300, display: "flex", flexDirection: "column", padding: 0, overflow: "hidden" }}>
        <div style={{ padding: "18px 20px 14px", borderBottom: "1px solid var(--border)", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <h2 style={{ fontSize: 17, fontWeight: 700, margin: 0 }}>💬 Groups</h2>
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={() => { setShowModal("create"); setModalError(""); }}
              className="btn btn-primary" style={{ padding: "6px 12px", fontSize: 12, borderRadius: 8 }}>
              + Create
            </button>
            <button onClick={() => { setShowModal("join"); setModalError(""); }}
              className="btn btn-secondary" style={{ padding: "6px 12px", fontSize: 12, borderRadius: 8 }}>
              Join
            </button>
          </div>
        </div>

        <div style={{ flex: 1, overflowY: "auto" }}>
          {loading ? (
            <div style={{ padding: 20, textAlign: "center", color: "var(--text-muted)", fontSize: 13 }}>Loading...</div>
          ) : groups.length === 0 ? (
            <div style={{ padding: 24, textAlign: "center", color: "var(--text-muted)" }}>
              <div style={{ fontSize: 36, marginBottom: 12 }}>👥</div>
              <div style={{ fontWeight: 600, marginBottom: 6 }}>No groups yet</div>
              <div style={{ fontSize: 12 }}>Create one or join with a code</div>
            </div>
          ) : groups.map(g => (
            <div key={g.id} onClick={() => setActiveGroup(g)}
              style={{
                padding: "14px 18px", cursor: "pointer", transition: "all 0.15s",
                background: activeGroup?.id === g.id ? "rgba(108,99,255,0.12)" : "transparent",
                borderLeft: activeGroup?.id === g.id ? "3px solid var(--brand-primary)" : "3px solid transparent",
              }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
                <div style={{ fontWeight: 600, fontSize: 14, color: "white" }}>{g.name}</div>
                <div style={{ fontSize: 11, color: "var(--text-muted)" }}>{g.member_count} members</div>
              </div>
              <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 4 }}>
                <span style={{ fontSize: 11, color: "var(--text-muted)", fontFamily: "monospace", background: "rgba(255,255,255,0.06)", padding: "2px 8px", borderRadius: 6 }}>
                  {g.join_code}
                </span>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Right: Chat */}
      <div className="dash-card" style={{ flex: 1, display: "flex", flexDirection: "column", padding: 0, overflow: "hidden" }}>
        {activeGroup ? (
          <>
            {/* Header */}
            <div style={{ padding: "16px 24px", borderBottom: "1px solid var(--border)", display: "flex", alignItems: "center", justifyContent: "space-between", background: "rgba(255,255,255,0.02)" }}>
              <div>
                <h3 style={{ margin: 0, fontSize: 16, fontWeight: 700 }}>{activeGroup.name}</h3>
                {activeGroup.description && (
                  <div style={{ fontSize: 12, color: "var(--text-muted)", marginTop: 2 }}>{activeGroup.description}</div>
                )}
              </div>
              <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                <div style={{ fontSize: 12, color: "var(--text-secondary)" }}>
                  Join Code:
                </div>
                <button onClick={() => copyCode(activeGroup.join_code)}
                  style={{ background: "rgba(108,99,255,0.15)", border: "1px solid rgba(108,99,255,0.3)", color: "#a78bfa", fontFamily: "monospace", fontWeight: 800, fontSize: 14, padding: "4px 12px", borderRadius: 8, cursor: "pointer", letterSpacing: 2 }}>
                  {activeGroup.join_code}
                </button>
                {copied && <span style={{ fontSize: 12, color: "var(--success)" }}>✓ Copied!</span>}
              </div>
            </div>

            {/* Messages */}
            <div style={{ flex: 1, overflowY: "auto", padding: "20px 24px", display: "flex", flexDirection: "column", gap: 12 }}>
              <AnimatePresence initial={false}>
                {messages.length === 0 ? (
                  <div style={{ margin: "auto", textAlign: "center", color: "var(--text-muted)" }}>
                    <div style={{ fontSize: 40, marginBottom: 12 }}>💬</div>
                    <div style={{ fontWeight: 600 }}>No messages yet</div>
                    <div style={{ fontSize: 13, marginTop: 6 }}>Be the first to say something!</div>
                  </div>
                ) : messages.map(msg => {
                  const isMe = msg.user_id === currentUserId;
                  return (
                    <motion.div key={msg.id}
                      initial={{ opacity: 0, y: 8 }}
                      animate={{ opacity: 1, y: 0 }}
                      transition={{ duration: 0.2 }}
                      style={{ alignSelf: isMe ? "flex-end" : "flex-start", maxWidth: "70%" }}>
                      {!isMe && (
                        <div style={{ fontSize: 11, color: "var(--text-muted)", marginBottom: 4, paddingLeft: 4 }}>{msg.user_name}</div>
                      )}
                      <div style={{
                        padding: "10px 16px", borderRadius: 16,
                        borderBottomRightRadius: isMe ? 4 : 16,
                        borderTopLeftRadius: isMe ? 16 : 4,
                        background: isMe ? "linear-gradient(135deg, var(--brand-primary), #a78bfa)" : "var(--surface)",
                        color: "white", fontSize: 14, lineHeight: 1.5,
                        border: isMe ? "none" : "1px solid var(--border)",
                        boxShadow: "0 2px 8px rgba(0,0,0,0.1)",
                      }}>
                        {msg.content}
                      </div>
                      <div style={{ fontSize: 10, color: "var(--text-muted)", marginTop: 4, textAlign: isMe ? "right" : "left", padding: "0 4px" }}>
                        {new Date(msg.created_at).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}
                      </div>
                    </motion.div>
                  );
                })}
              </AnimatePresence>
              <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <form onSubmit={sendMessage} style={{ padding: "16px 24px", borderTop: "1px solid var(--border)", display: "flex", gap: 12 }}>
              <input
                type="text" value={input} onChange={e => setInput(e.target.value)}
                placeholder={`Message #${activeGroup.name}...`}
                className="input-field"
                style={{ flex: 1, borderRadius: 24, padding: "12px 20px" }}
              />
              <button disabled={!input.trim() || sending} type="submit"
                className="btn btn-primary"
                style={{ width: 48, height: 48, borderRadius: 24, padding: 0, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18 }}>
                ➤
              </button>
            </form>
          </>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", height: "100%", color: "var(--text-muted)" }}>
            <div style={{ fontSize: 60, marginBottom: 20 }}>👥</div>
            <h3 style={{ marginBottom: 8 }}>Select a Group</h3>
            <p style={{ fontSize: 14, maxWidth: 300, textAlign: "center" }}>
              Create a group or join one with a 6-character code to start chatting.
            </p>
          </div>
        )}
      </div>

      {/* Modal */}
      <AnimatePresence>
        {showModal && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            onClick={() => setShowModal(null)}
            style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.7)", zIndex: 100, display: "flex", alignItems: "center", justifyContent: "center" }}>
            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }}
              onClick={e => e.stopPropagation()}
              className="dash-card"
              style={{ width: 400, padding: 32, border: "1px solid var(--border)" }}>
              <h2 style={{ fontSize: 20, fontWeight: 800, marginBottom: 24 }}>
                {showModal === "create" ? "Create Group" : "Join Group"}
              </h2>

              {showModal === "create" ? (
                <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
                  <div>
                    <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: "var(--text-secondary)", marginBottom: 6 }}>Group Name *</label>
                    <input value={modalInput.name} onChange={e => setModalInput(p => ({ ...p, name: e.target.value }))}
                      placeholder="e.g. MERN Stack Builders"
                      className="input-field" style={{ width: "100%", padding: "10px 14px" }} />
                  </div>
                  <div>
                    <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: "var(--text-secondary)", marginBottom: 6 }}>Description (optional)</label>
                    <input value={modalInput.description} onChange={e => setModalInput(p => ({ ...p, description: e.target.value }))}
                      placeholder="What's this group about?"
                      className="input-field" style={{ width: "100%", padding: "10px 14px" }} />
                  </div>
                </div>
              ) : (
                <div>
                  <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: "var(--text-secondary)", marginBottom: 6 }}>Enter 6-Character Join Code</label>
                  <input value={modalInput.code} onChange={e => setModalInput(p => ({ ...p, code: e.target.value.toUpperCase() }))}
                    placeholder="A7X92K"
                    maxLength={6}
                    className="input-field"
                    style={{ width: "100%", padding: "10px 14px", fontFamily: "monospace", fontSize: 20, letterSpacing: 4, textAlign: "center" }} />
                </div>
              )}

              {modalError && (
                <div style={{ marginTop: 12, padding: "10px 14px", background: "rgba(239,68,68,0.1)", border: "1px solid rgba(239,68,68,0.3)", borderRadius: 8, fontSize: 13, color: "#f87171" }}>
                  {modalError}
                </div>
              )}

              <div style={{ display: "flex", gap: 12, marginTop: 24 }}>
                <button onClick={() => setShowModal(null)} className="btn btn-secondary" style={{ flex: 1, padding: "11px 0", borderRadius: 10 }}>Cancel</button>
                <button onClick={showModal === "create" ? handleCreate : handleJoin}
                  className="btn btn-primary" style={{ flex: 1, padding: "11px 0", borderRadius: 10 }}>
                  {showModal === "create" ? "Create Group" : "Join Group"}
                </button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useSession } from "next-auth/react";
import { hackathonApi } from "@/lib/api";

const FALLBACK_HACKATHONS = [
  {
    id: 1, title: "Global AI Hackathon 2026", organizer: "Anthropic & OpenAI",
    deadline: "April 15-17, 2026", prize_pool: "$250,000", participants_count: 4500,
    tags: "LLMs,RAG,Agents", status: "Upcoming", bookmarked: false,
    image_url: "https://images.unsplash.com/photo-1677442136019-21780ecad995?w=800&auto=format&fit=crop&q=60",
    registration_link: "https://devpost.com",
  },
  {
    id: 2, title: "ETH Global Spring", organizer: "Ethereum Foundation",
    deadline: "May 1-3, 2026", prize_pool: "$100,000", participants_count: 2100,
    tags: "Web3,Smart Contracts,DeFi", status: "Open", bookmarked: false,
    image_url: "https://images.unsplash.com/photo-1622737133809-d95047b9e673?w=800&auto=format&fit=crop&q=60",
    registration_link: "https://ethglobal.com",
  },
  {
    id: 3, title: "FinTech Appathon", organizer: "Stripe",
    deadline: "May 20-22, 2026", prize_pool: "$50,000", participants_count: 1200,
    tags: "Payments,SaaS,Mobile", status: "Upcoming", bookmarked: false,
    image_url: "https://images.unsplash.com/photo-1559526324-4b87b5e36e44?w=800&auto=format&fit=crop&q=60",
    registration_link: "https://stripe.com",
  },
  {
    id: 4, title: "Tulasi Internal Buildathon", organizer: "Tulasi AI",
    deadline: "June 5-7, 2026", prize_pool: "Summer Internships", participants_count: 500,
    tags: "Education,React,FastAPI", status: "Open", bookmarked: false,
    image_url: "https://images.unsplash.com/photo-1522071820081-009f0129c71c?w=800&auto=format&fit=crop&q=60",
    registration_link: "https://tulasiai.vercel.app",
  },
];

function HackathonSkeleton() {
  return (
    <div style={{ borderRadius: 24, overflow: "hidden", background: "rgba(255,255,255,0.02)", border: "1px solid rgba(255,255,255,0.06)", height: 420 }}>
      <div style={{ height: 180, background: "rgba(255,255,255,0.04)" }} />
      <div style={{ padding: 24 }}>
        <div style={{ height: 24, width: "70%", borderRadius: 8, background: "rgba(255,255,255,0.06)", marginBottom: 12 }} />
        <div style={{ height: 16, width: "40%", borderRadius: 8, background: "rgba(255,255,255,0.04)", marginBottom: 24 }} />
        <div style={{ height: 44, borderRadius: 12, background: "rgba(255,255,255,0.04)" }} />
      </div>
    </div>
  );
}

export default function HackathonsPage() {
  const { data: session } = useSession();
  const token = typeof window !== "undefined" ? localStorage.getItem("token") || "" : "";

  const [filter, setFilter] = useState("All");
  const [hackathons, setHackathons] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [bookmarking, setBookmarking] = useState<Set<number>>(new Set());

  useEffect(() => {
    const fetchHackathons = async () => {
      setLoading(true);
      try {
        const data = await hackathonApi.list(undefined, filter !== "All" ? filter : undefined, token);
        const list = data.hackathons ?? [];
        setHackathons(list.length > 0 ? list : FALLBACK_HACKATHONS);
      } catch (e) {
        setHackathons(FALLBACK_HACKATHONS);
      } finally {
        setLoading(false);
      }
    };
    fetchHackathons();
  }, [filter, token]);

  const toggleBookmark = async (hack: any) => {
        setBookmarking(prev => new Set(prev).add(hack.id));
    try {
      if (hack.bookmarked) {
        await hackathonApi.unbookmark(hack.id, token);
      } else {
        await hackathonApi.bookmark(hack.id, token);
      }
      setHackathons(prev => prev.map(h => h.id === hack.id ? { ...h, bookmarked: !h.bookmarked } : h));
    } catch (e) {}
    setBookmarking(prev => { const s = new Set(prev); s.delete(hack.id); return s; });
  };

  return (
    <div style={{ maxWidth: 1200, margin: "0 auto", paddingBottom: 60 }}>

      <div style={{ textAlign: "center", marginBottom: 40 }}>
        <h1 style={{ fontSize: 36, fontWeight: 800, fontFamily: "var(--font-outfit)", marginBottom: 12 }}>
          Global <span className="gradient-text">Hackathons</span>
        </h1>
        <p style={{ color: "var(--text-secondary)", fontSize: 16, maxWidth: 600, margin: "0 auto" }}>
          Build projects, win prizes, and get hired. Browse top vetted hackathons happening globally this season.
        </p>
      </div>

      {/* Filters */}
      <div style={{ display: "flex", justifyContent: "center", gap: 12, marginBottom: 40, flexWrap: "wrap" }}>
        {["All", "Open", "Upcoming", "Past"].map(status => (
          <button key={status} onClick={() => setFilter(status)}
            style={{
              background: filter === status ? "var(--brand-primary)" : "rgba(108,99,255,0.05)",
              color: filter === status ? "var(--bg-primary)" : "var(--text-muted)",
              border: filter === status ? "1px solid var(--brand-primary)" : "1px solid var(--border)",
              padding: "8px 24px", borderRadius: 24, fontSize: 14, fontWeight: 700, cursor: "pointer", transition: "all 0.2s"
            }}>
            {status}
          </button>
        ))}
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(340px, 1fr))", gap: 28 }}>
        {loading ? (
          [1, 2, 3, 4].map(i => <HackathonSkeleton key={i} />)
        ) : (
          <AnimatePresence>
            {hackathons.length > 0 ? hackathons.map((hack) => (
              <motion.div
                key={hack.id}
                initial={{ opacity: 0, y: 16 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, scale: 0.95 }}
                whileHover={{ y: -6, scale: 1.01 }}
                transition={{ duration: 0.25 }}
                className="glass-card"
                style={{ padding: 0, overflow: "hidden", border: "1px solid rgba(255,255,255,0.08)", display: "flex", flexDirection: "column", background: "rgba(255,255,255,0.02)" }}>
                
                {/* Banner */}
                <div style={{ position: "relative", height: 180, overflow: "hidden", background: "#0f0f1a" }}>
                  <div style={{ position: "absolute", inset: 0, backgroundImage: `url(${hack.image_url})`, backgroundSize: "cover", backgroundPosition: "center", filter: "brightness(0.6)" }} />
                  <div style={{ position: "absolute", top: 14, left: 14, background: "rgba(0,0,0,0.55)", backdropFilter: "blur(10px)", padding: "5px 14px", borderRadius: 20, fontSize: 12, fontWeight: 700, color: "white", border: "1px solid rgba(255,255,255,0.2)" }}>
                    {hack.deadline || "Date TBD"}
                  </div>
                  <div style={{ position: "absolute", top: 14, right: 14, background: hack.status === "Open" ? "#22c55e" : "var(--brand-primary)", padding: "4px 12px", borderRadius: 8, fontSize: 11, fontWeight: 800, color: "white" }}>
                    {hack.status || "Open"}
                  </div>
                  <div style={{ position: "absolute", bottom: 12, left: 14, display: "flex", gap: 6, flexWrap: "wrap", right: 14 }}>
                    {(hack.tags || "").split(",").slice(0, 3).map((tag: string) => (
                      <span key={tag} style={{ background: "rgba(124,58,237,0.85)", backdropFilter: "blur(4px)", padding: "3px 10px", borderRadius: 10, fontSize: 11, fontWeight: 700, color: "white" }}>
                        {tag.trim()}
                      </span>
                    ))}
                  </div>
                </div>

                {/* Content */}
                <div style={{ padding: 22, flex: 1, display: "flex", flexDirection: "column", background: "var(--bg-card)" }}>
                  <h2 style={{ fontSize: 20, fontWeight: 800, color: "var(--text-primary)", marginBottom: 4, lineHeight: 1.3 }}>{hack.title}</h2>
                  <p style={{ fontSize: 13, color: "var(--text-secondary)", fontWeight: 600, marginBottom: 18 }}>By {hack.organizer || "Organizer"}</p>

                  <div style={{ display: "flex", gap: 24, marginBottom: 22 }}>
                    <div>
                      <div style={{ fontSize: 11, color: "var(--text-muted)", textTransform: "uppercase", letterSpacing: "1px", fontWeight: 700, marginBottom: 3 }}>Prize Pool</div>
                      <div style={{ fontSize: 17, fontWeight: 800, color: "var(--brand-primary)" }}>{hack.prize_pool || "–"}</div>
                    </div>
                    <div>
                      <div style={{ fontSize: 11, color: "var(--text-muted)", textTransform: "uppercase", letterSpacing: "1px", fontWeight: 700, marginBottom: 3 }}>Builders</div>
                      <div style={{ fontSize: 17, fontWeight: 800, color: "var(--text-primary)" }}>{(hack.participants_count ?? 0).toLocaleString()}</div>
                    </div>
                  </div>

                  <div style={{ marginTop: "auto", display: "flex", gap: 10 }}>
                    <button
                      onClick={() => hack.registration_link && window.open(hack.registration_link, "_blank")}
                      className="btn-primary" style={{ flex: 1, padding: 13, borderRadius: 12, fontWeight: 700, fontSize: 14 }}>
                      Apply Now →
                    </button>
                    <button
                      onClick={() => toggleBookmark(hack)}
                      disabled={bookmarking.has(hack.id)}
                      title={hack.bookmarked ? "Remove bookmark" : "Bookmark this hackathon"}
                      style={{
                        padding: "0 16px", borderRadius: 12, fontSize: 18,
                        background: hack.bookmarked ? "rgba(251,191,36,0.15)" : "var(--background)",
                        border: hack.bookmarked ? "1px solid rgba(251,191,36,0.4)" : "1px solid var(--border)",
                        cursor: "pointer", transition: "all 0.2s",
                        opacity: bookmarking.has(hack.id) ? 0.6 : 1,
                      }}>
                      {hack.bookmarked ? "🔖" : "🏷️"}
                    </button>
                  </div>
                </div>
              </motion.div>
            )) : (
              <div style={{ gridColumn: "1 / -1", textAlign: "center", padding: 80, color: "var(--text-muted)", fontSize: 16 }}>
                <div style={{ fontSize: 48, marginBottom: 16 }}>🏆</div>
                <div style={{ fontWeight: 700, fontSize: 18, marginBottom: 8, color: "var(--text-secondary)" }}>No Hackathons Found</div>
                Stay tuned — new events are added regularly!
              </div>
            )}
          </AnimatePresence>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { motion } from "framer-motion";
import { useSession } from "next-auth/react";

const BACKEND = "";

const TYPE_FILTERS = [
  { id: "all", label: "All", icon: "🕐" },
  { id: "code_solved", label: "Code Solved", icon: "💻" },
  { id: "video_watched", label: "Videos", icon: "▶️" },
  { id: "interview_completed", label: "Interviews", icon: "🎯" },
  { id: "roadmap_step", label: "Roadmap", icon: "🗺️" },
  { id: "hackathon_joined", label: "Hackathons", icon: "🏆" },
];

interface HistoryItem {
  id: number;
  action_type: string;
  icon: string;
  title: string;
  xp_earned: number;
  created_at: string;
}

export default function HistoryPage() {
  const { data: session } = useSession();
  const [filter, setFilter] = useState("all");
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);
  const [error, setError] = useState("");

  useEffect(() => {
    if (session) fetchHistory();
  }, [filter, page, session]);

  const fetchHistory = async () => {
    setLoading(true);
    try {
      const token = typeof window !== "undefined" ? localStorage.getItem("token") || "" : "";
      

      const params = new URLSearchParams({ page: String(page), limit: "20" });
      if (filter !== "all") params.set("action_type", filter);

      const res = await fetch(`${BACKEND}/api/activity/history?${params}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setHistory(data.history || []);
        setTotal(data.total || 0);
      }
    } catch (e) {
      setError("Could not load activity history. Make sure you are logged in.");
    } finally {
      setLoading(false);
    }
  };

  const formatDate = (iso: string) => {
    const d = new Date(iso);
    const now = new Date();
    const diff = Math.floor((now.getTime() - d.getTime()) / 1000);
    if (diff < 60) return "Just now";
    if (diff < 3600) return `${Math.floor(diff / 60)}m ago`;
    if (diff < 86400) return `${Math.floor(diff / 3600)}h ago`;
    if (diff < 604800) return `${Math.floor(diff / 86400)}d ago`;
    return d.toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" });
  };

  const ACTION_COLORS: Record<string, string> = {
    code_solved: "#4ECDC4", video_watched: "#6C63FF", reel_watched: "#FF6B9D",
    interview_completed: "#FFD93D", roadmap_step: "#43E97B", hackathon_joined: "#FF8E53",
    roadmap_completed: "#A78BFA", course_completed: "#06B6D4",
  };

  return (
    <div style={{ maxWidth: 900, margin: "0 auto", paddingBottom: 60 }}>
      <div style={{ marginBottom: 32 }}>
        <h1 style={{ fontSize: 28, fontWeight: 800, fontFamily: "Outfit", marginBottom: 8 }}>📊 Activity History</h1>
        <p style={{ color: "var(--text-secondary)", fontSize: 14 }}>Track everything you&apos;ve done — every problem solved, video watched, and interview completed.</p>
      </div>

      {/* Filter Tabs */}
      <div style={{ display: "flex", gap: 8, marginBottom: 28, flexWrap: "wrap" }}>
        {TYPE_FILTERS.map(f => (
          <button key={f.id} onClick={() => { setFilter(f.id); setPage(1); }}
            style={{
              padding: "7px 16px", borderRadius: 20, cursor: "pointer", fontSize: 13, fontWeight: 600,
              background: filter === f.id ? "rgba(108,99,255,0.2)" : "rgba(255,255,255,0.04)",
              color: filter === f.id ? "#9B95FF" : "var(--text-muted)",
              border: filter === f.id ? "1px solid rgba(108,99,255,0.3)" : "1px solid rgba(255,255,255,0.06)",
              transition: "all 0.2s",
            }}>
            {f.icon} {f.label}
          </button>
        ))}
      </div>

      {/* Total count */}
      {!loading && !error && (
        <div style={{ fontSize: 13, color: "var(--text-muted)", marginBottom: 20 }}>
          Showing {history.length} of {total} activities
        </div>
      )}

      {error && (
        <div style={{ background: "rgba(255,107,107,0.1)", border: "1px solid rgba(255,107,107,0.3)", borderRadius: 12, padding: 20, color: "#FF6B6B", textAlign: "center", marginBottom: 24 }}>
          {error}
        </div>
      )}

      {loading ? (
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          {[...Array(5)].map((_, i) => (
            <div key={i} style={{ height: 72, background: "rgba(255,255,255,0.03)", borderRadius: 12, border: "1px solid rgba(255,255,255,0.05)", animation: "pulse 1.5s infinite" }} />
          ))}
        </div>
      ) : history.length === 0 ? (
        <div style={{ textAlign: "center", padding: "60px 20px" }}>
          <div style={{ fontSize: 48, marginBottom: 16 }}>📭</div>
          <h3 style={{ fontSize: 18, fontWeight: 700, marginBottom: 8 }}>No activity yet</h3>
          <p style={{ color: "var(--text-secondary)", fontSize: 14 }}>Start learning! Solve problems, watch videos, or do a mock interview.</p>
        </div>
      ) : (
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {history.map((item, i) => {
            const color = ACTION_COLORS[item.action_type] || "#6C63FF";
            return (
              <motion.div key={item.id}
                initial={{ opacity: 0, x: -16 }} animate={{ opacity: 1, x: 0 }} transition={{ delay: i * 0.04 }}
                style={{
                  display: "flex", alignItems: "center", gap: 16, padding: "16px 20px",
                  background: "var(--bg-card)", border: "1px solid rgba(255,255,255,0.06)",
                  borderLeft: `3px solid ${color}`, borderRadius: 12, transition: "border-color 0.2s",
                }}
                whileHover={{ borderColor: "rgba(255,255,255,0.12)" }}
              >
                <div style={{ width: 40, height: 40, borderRadius: 10, background: `${color}20`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20, flexShrink: 0 }}>
                  {item.icon}
                </div>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontSize: 14, fontWeight: 600, color: "white", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{item.title}</div>
                  <div style={{ fontSize: 11, color: "var(--text-muted)", marginTop: 3 }}>{formatDate(item.created_at)}</div>
                </div>
                <div style={{ fontSize: 13, fontWeight: 700, color, flexShrink: 0 }}>+{item.xp_earned} XP</div>
              </motion.div>
            );
          })}
        </div>
      )}

      {/* Pagination */}
      {total > 20 && (
        <div style={{ display: "flex", justifyContent: "center", gap: 12, marginTop: 32 }}>
          <button onClick={() => setPage(Math.max(1, page - 1))} disabled={page === 1}
            style={{ padding: "8px 20px", borderRadius: 10, background: "rgba(255,255,255,0.05)", border: "1px solid rgba(255,255,255,0.1)", color: "white", cursor: page === 1 ? "default" : "pointer", opacity: page === 1 ? 0.4 : 1 }}>
            ← Prev
          </button>
          <span style={{ padding: "8px 16px", color: "var(--text-secondary)", fontSize: 13 }}>Page {page} of {Math.ceil(total / 20)}</span>
          <button onClick={() => setPage(page + 1)} disabled={page >= Math.ceil(total / 20)}
            style={{ padding: "8px 20px", borderRadius: 10, background: "rgba(255,255,255,0.05)", border: "1px solid rgba(255,255,255,0.1)", color: "white", cursor: "pointer", opacity: page >= Math.ceil(total / 20) ? 0.4 : 1 }}>
            Next →
          </button>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useSession } from "next-auth/react";

import { interviewApi } from "@/lib/api";
import { trackEvent } from "@/lib/analytics";

const ROLES = [
  "Software Engineer", "AI Engineer", "Data Scientist", "Backend Developer",
  "Frontend Developer", "DevOps Engineer", "Product Manager", "QA Engineer",
  "Cybersecurity Engineer", "Full Stack Developer", "ML Engineer", "Cloud Engineer",
];

const INTERVIEW_TYPES = [
  { id: "Technical", icon: "⚙️", desc: "DSA, problem-solving, and programming concepts" },
  { id: "HR / Behavioral", icon: "🎤", desc: "STAR method, leadership, and culture fit" },
  { id: "System Design", icon: "🏗️", desc: "Architecture, scalability, and design patterns" },
  { id: "Coding", icon: "💻", desc: "Live coding problems and walkthrough" },
];

const COMPANIES = [
  "Google", "Amazon", "Meta", "Apple", "Netflix", "Microsoft",
  "Startup", "Any Company", "TCS", "Infosys", "IBM", "Deloitte",
];

interface Feedback {
  score: number; grade: string; feedback_summary: string;
  strengths: string[]; improvements: string[]; recommendation: string;
}

export default function InterviewPage() {
  const { data: session } = useSession();
  const [role, setRole] = useState(ROLES[0]);
  const [company, setCompany] = useState(COMPANIES[0]);
  const [interviewType, setInterviewType] = useState("Technical");
  const [numQuestions, setNumQuestions] = useState(5);
  const [phase, setPhase] = useState<"setup" | "active" | "feedback">("setup");
  const [sessionId, setSessionId] = useState("");
  const [currentQuestion, setCurrentQuestion] = useState("");
  const [answer, setAnswer] = useState("");
  const [questionNum, setQuestionNum] = useState(1);
  const [feedback, setFeedback] = useState<Feedback | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [timeLeft, setTimeLeft] = useState(120); // 2 minutes per question
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [voiceEnabled, setVoiceEnabled] = useState(false);

  // Timer logic
  useEffect(() => {
    let timer: NodeJS.Timeout;
    if (phase === "active" && timeLeft > 0 && !loading) {
      timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0 && phase === "active") {
      submitAnswer(); // Auto-submit when time's up
    }
    return () => clearInterval(timer);
  }, [phase, timeLeft, loading]);

  // Reset timer on new question
  useEffect(() => {
    if (currentQuestion) {
      setTimeLeft(120);
      if (voiceEnabled) speakQuestion(currentQuestion);
    }
  }, [currentQuestion]);

  const speakQuestion = (text: string) => {
    if (!window.speechSynthesis) return;
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.onstart = () => setIsSpeaking(true);
    utterance.onend = () => setIsSpeaking(false);
    window.speechSynthesis.speak(utterance);
  };

  const startListening = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return;
    const recognition = new SpeechRecognition();
    recognition.continuous = false;
    recognition.interimResults = false;
    recognition.onstart = () => setIsListening(true);
    recognition.onend = () => setIsListening(false);
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      setAnswer(prev => prev + (prev ? " " : "") + transcript);
    };
    recognition.start();
  };


  const startInterview = async () => {
    setLoading(true); setError("");

    trackEvent("interview_started", { role, company, type: interviewType });

    try {
      const token = typeof window !== "undefined" ? localStorage.getItem("token") || "" : "";
      
      
      const data = await interviewApi.start(role, company, interviewType, token);
      
      setSessionId(data.session_id);
      setCurrentQuestion(data.question);
      setQuestionNum(1);
      setPhase("active");
    } catch (e: unknown) {
      const error = e as Error;
      setError(error.message || "Failed to start interview. The backend might be sleeping. Please try again.");
    } finally { setLoading(false); }
  };

  const submitAnswer = async () => {
    if (!answer.trim()) return;
    setLoading(true); setError("");
    try {
      const token = typeof window !== "undefined" ? localStorage.getItem("token") || "" : "";
            const data = await interviewApi.answer(answer, sessionId, token);
      
      setAnswer("");
      if ((data as any).status === "completed") {
        setFeedback((data as any).feedback);
        setPhase("feedback");
      } else {
        setCurrentQuestion(data.next_question || "End of Interview");
        if (data.next_question) {
           setQuestionNum(prev => prev + 1);
        } else {
           // Handle end of interview if next_question is missing
           setPhase("feedback");
        }
      }
    } catch (e: unknown) {
      const error = e as Error;
      setError(error.message || "Error submitting answer. The backend might be sleeping. Please try again.");
    } finally { setLoading(false); }
  };

  const reset = () => {
    setPhase("setup"); setSessionId(""); setCurrentQuestion(""); setAnswer(""); setFeedback(null); setError(""); setQuestionNum(1);
  };

  const SCORE_COLOR = (score: number) => score >= 80 ? "#43E97B" : score >= 60 ? "#FFD93D" : "#FF6B6B";
  const GRADE_EMOJI: Record<string, string> = { "Excellent": "🏆", "Good": "👍", "Average": "📊", "Needs Improvement": "📈" };

  return (
    <div style={{ maxWidth: 900, margin: "0 auto", paddingBottom: 60 }}>
      <div style={{ textAlign: "center", marginBottom: 36 }}>
        <h1 style={{ fontSize: 32, fontWeight: 800, fontFamily: "var(--font-outfit)", marginBottom: 10 }}>
          AI <span style={{ background: "linear-gradient(135deg, #FFD93D, #FF6B6B)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>Mock Interviews</span>
        </h1>
        <p style={{ color: "var(--text-secondary)", fontSize: 15, maxWidth: 500, margin: "0 auto" }}>
          Real AI interviewer. 9 roles. 4 types. Instant scoring & feedback.
        </p>
      </div>

      {error && (
        <div style={{ background: "rgba(255,107,107,0.1)", border: "1px solid rgba(255,107,107,0.3)", borderRadius: 12, padding: "12px 16px", color: "#FF6B6B", marginBottom: 24, fontSize: 14 }}>
          ⚠️ {error}
        </div>
      )}

      <AnimatePresence mode="wait">

        {/* SETUP PHASE */}
        {phase === "setup" && (
          <motion.div key="setup" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}>
            <div className="dash-card" style={{ padding: 36, marginBottom: 24 }}>
              <h2 style={{ fontSize: 18, fontWeight: 700, marginBottom: 24 }}>🎯 Configure Your Interview</h2>

              {/* Role select */}
              <div style={{ marginBottom: 20 }}>
                <label style={{ display: "block", fontSize: 13, fontWeight: 700, color: "var(--text-secondary)", marginBottom: 8, textTransform: "uppercase", letterSpacing: "1px" }}>Role</label>
                <div style={{ display: "flex", flexWrap: "wrap", gap: 8 }}>
                  {ROLES.map(r => (
                    <button key={r} onClick={() => setRole(r)}
                      style={{
                        padding: "7px 14px", borderRadius: 20, cursor: "pointer", fontSize: 13, fontWeight: 600,
                        background: role === r ? "rgba(108,99,255,0.2)" : "rgba(255,255,255,0.04)",
                        color: role === r ? "#9B95FF" : "var(--text-muted)",
                        border: role === r ? "1px solid rgba(108,99,255,0.4)" : "1px solid rgba(255,255,255,0.07)",
                        transition: "all 0.2s",
                      }}>{r}</button>
                  ))}
                </div>
              </div>

              {/* Type */}
              <div style={{ marginBottom: 20 }}>
                <label style={{ display: "block", fontSize: 13, fontWeight: 700, color: "var(--text-secondary)", marginBottom: 8, textTransform: "uppercase", letterSpacing: "1px" }}>Interview Type</label>
                <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(200px, 1fr))", gap: 12 }}>
                  {INTERVIEW_TYPES.map(t => (
                    <button key={t.id} onClick={() => setInterviewType(t.id)}
                      style={{
                        padding: "12px 16px", borderRadius: 12, cursor: "pointer", textAlign: "left",
                        background: interviewType === t.id ? "rgba(78,205,196,0.15)" : "rgba(255,255,255,0.03)",
                        border: interviewType === t.id ? "1px solid rgba(78,205,196,0.4)" : "1px solid rgba(255,255,255,0.07)",
                        transition: "all 0.2s",
                      }}>
                      <div style={{ fontSize: 20, marginBottom: 4 }}>{t.icon}</div>
                      <div style={{ fontSize: 13, fontWeight: 700, color: interviewType === t.id ? "#4ECDC4" : "var(--text-primary)" }}>{t.id}</div>
                      <div style={{ fontSize: 11, color: "var(--text-muted)", marginTop: 3 }}>{t.desc}</div>
                    </button>
                  ))}
                </div>
              </div>

              {/* Company & Questions */}
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 28 }}>
                <div>
                  <label style={{ display: "block", fontSize: 13, fontWeight: 700, color: "var(--text-secondary)", marginBottom: 8, textTransform: "uppercase", letterSpacing: "1px" }}>Company</label>
                  <select value={company} onChange={e => setCompany(e.target.value)} className="input-field">
                    {COMPANIES.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
                <div>
                  <label style={{ display: "block", fontSize: 13, fontWeight: 700, color: "var(--text-secondary)", marginBottom: 8, textTransform: "uppercase", letterSpacing: "1px" }}>Questions: {numQuestions}</label>
                  <input type="range" min={3} max={10} value={numQuestions} onChange={e => setNumQuestions(+e.target.value)}
                    style={{ width: "100%", marginTop: 12 }} />
                  <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, color: "var(--text-muted)" }}><span>3 quick</span><span>10 full</span></div>
                </div>
              </div>

              <motion.button whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }} onClick={startInterview} disabled={loading}
                style={{ width: "100%", padding: "16px", borderRadius: 14, background: "linear-gradient(135deg, #6C63FF, #4ECDC4)", border: "none", color: "white", fontWeight: 800, fontSize: 17, cursor: loading ? "default" : "pointer", opacity: loading ? 0.7 : 1 }}>
                {loading ? "Starting Interview..." : `Start ${interviewType} Interview at ${company} →`}
              </motion.button>
            </div>
          </motion.div>
        )}

        {/* ACTIVE PHASE */}
        {phase === "active" && (
          <motion.div key="active" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
              <div>
                <span style={{ fontSize: 13, color: "var(--text-muted)" }}>{role} @ {company} • {interviewType}</span>
              </div>
              <div style={{ background: "rgba(108,99,255,0.15)", border: "1px solid rgba(108,99,255,0.3)", borderRadius: 20, padding: "4px 14px", fontSize: 13, fontWeight: 700, color: "#9B95FF" }}>
                Q{questionNum}/{numQuestions}
              </div>
            </div>

            <div style={{ height: 4, background: "rgba(255,255,255,0.06)", borderRadius: 4, marginBottom: 12 }}>
              <div style={{ height: "100%", width: `${(questionNum / numQuestions) * 100}%`, background: "linear-gradient(90deg, #6C63FF, #4ECDC4)", borderRadius: 4, transition: "width 0.5s ease" }} />
            </div>

            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 24 }}>
               <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                  <button 
                    onClick={() => setVoiceEnabled(!voiceEnabled)}
                    style={{ background: voiceEnabled ? "rgba(78,205,196,0.2)" : "rgba(255,255,255,0.05)", border: `1px solid ${voiceEnabled ? "#4ECDC4" : "rgba(255,255,255,0.1)"}`, color: voiceEnabled ? "#4ECDC4" : "var(--text-muted)", padding: "6px 12px", borderRadius: 20, fontSize: 12, fontWeight: 700, cursor: "pointer", display: "flex", alignItems: "center", gap: 6 }}
                  >
                    {voiceEnabled ? "🔊 Voice On" : "📁 Voice Off"}
                  </button>
                  {voiceEnabled && (
                    <button onClick={() => speakQuestion(currentQuestion)} style={{ background: "none", border: "none", color: "#6C63FF", fontSize: 12, fontWeight: 600, cursor: "pointer" }}>Replay Audio</button>
                  )}
               </div>
               <div style={{ fontSize: 14, fontWeight: 800, color: timeLeft < 30 ? "#FF6B6B" : "#FFD93D", display: "flex", alignItems: "center", gap: 6 }}>
                  ⏱️ {Math.floor(timeLeft / 60)}:{(timeLeft % 60).toString().padStart(2, '0')}
               </div>
            </div>

            <div className="dash-card" style={{ padding: 32, marginBottom: 20, background: "rgba(108,99,255,0.05)", border: "1px solid rgba(108,99,255,0.2)" }}>
              <div style={{ display: "flex", alignItems: "flex-start", gap: 14, marginBottom: 20 }}>
                <div style={{ width: 44, height: 44, borderRadius: 12, background: "linear-gradient(135deg, #6C63FF, #4ECDC4)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 22, flexShrink: 0 }}>🤖</div>
                <div>
                  <div style={{ fontSize: 12, color: "#9B95FF", fontWeight: 700, marginBottom: 6 }}>AI INTERVIEWER</div>
                  <p style={{ fontSize: 16, lineHeight: 1.65, color: "var(--text-primary)", margin: 0 }}>{currentQuestion}</p>
                </div>
              </div>
            </div>

            <div style={{ position: "relative" }}>
              <textarea
                value={answer} onChange={e => setAnswer(e.target.value)}
                placeholder="Type your answer here... Take your time and be thorough."
                style={{
                  width: "100%", minHeight: 160, padding: "16px", borderRadius: 14, resize: "vertical",
                  background: "var(--background)", border: "1px solid var(--border)",
                  color: "var(--text-primary)", fontSize: 15, lineHeight: 1.6, fontFamily: "inherit", outline: "none", boxSizing: "border-box",
                }}
                onFocus={e => e.target.style.borderColor = "var(--brand-primary)"}
                onBlur={e => e.target.style.borderColor = "var(--border)"}
              />
              <button 
                onClick={startListening}
                style={{ 
                  position: "absolute", bottom: 16, right: 16, width: 40, height: 40, borderRadius: 20, 
                  background: isListening ? "#FF6B6B" : "rgba(108,99,255,0.2)", border: "none", color: "white", 
                  cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18,
                  boxShadow: isListening ? "0 0 15px rgba(255,107,107,0.5)" : "none"
                }}
              >
                {isListening ? "🔴" : "🎤"}
              </button>
            </div>

            <div style={{ display: "flex", gap: 12, marginTop: 16 }}>
              <motion.button whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }} onClick={submitAnswer} disabled={loading || !answer.trim()}
                style={{ flex: 1, padding: "14px", borderRadius: 12, background: "linear-gradient(135deg, #6C63FF, #4ECDC4)", border: "none", color: "white", fontWeight: 800, fontSize: 16, cursor: "pointer", opacity: loading || !answer.trim() ? 0.6 : 1 }}>
                {loading ? "Processing..." : questionNum >= numQuestions ? "Submit Final Answer 🏁" : "Next Question →"}
              </motion.button>
              <button onClick={reset} style={{ padding: "14px 20px", borderRadius: 12, background: "transparent", border: "1px solid rgba(255,107,107,0.3)", color: "#FF6B6B", fontWeight: 600, cursor: "pointer" }}>End</button>
            </div>
          </motion.div>
        )}

        {/* FEEDBACK PHASE */}
        {phase === "feedback" && feedback && (
          <motion.div key="feedback" initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0 }}>
            <div className="dash-card" style={{ padding: 40, textAlign: "center", marginBottom: 24, background: "rgba(255,255,255,0.02)" }}>

              <div style={{ fontSize: 48, marginBottom: 16 }}>{GRADE_EMOJI[feedback.grade] || "📋"}</div>

              <div style={{ fontSize: 80, fontWeight: 900, color: SCORE_COLOR(feedback.score), lineHeight: 1, marginBottom: 8 }}>{feedback.score}</div>
              <div style={{ fontSize: 14, color: "var(--text-secondary)", marginBottom: 8 }}>/ 100</div>

              <div style={{ display: "inline-flex", alignItems: "center", gap: 8, background: `${SCORE_COLOR(feedback.score)}20`, border: `1px solid ${SCORE_COLOR(feedback.score)}50`, borderRadius: 20, padding: "6px 20px", marginBottom: 20 }}>
                <span style={{ fontWeight: 800, fontSize: 16, color: SCORE_COLOR(feedback.score) }}>{feedback.grade}</span>
                <span style={{ color: "var(--text-secondary)", fontSize: 14 }}>• {feedback.recommendation}</span>
              </div>

              <p style={{ fontSize: 16, color: "var(--text-primary)", lineHeight: 1.7, maxWidth: 600, margin: "0 auto 32px" }}>{feedback.feedback_summary}</p>

              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20, textAlign: "left", marginBottom: 32 }}>
                <div style={{ background: "rgba(67,233,123,0.07)", border: "1px solid rgba(67,233,123,0.2)", borderRadius: 14, padding: 20 }}>
                  <h3 style={{ fontSize: 14, fontWeight: 700, color: "#43E97B", textTransform: "uppercase", letterSpacing: "1px", marginBottom: 14 }}>✅ Strengths</h3>
                  {feedback.strengths.map((s, i) => (
                    <div key={i} style={{ fontSize: 13, color: "var(--text-primary)", marginBottom: 8, display: "flex", gap: 8 }}>
                      <span style={{ color: "#43E97B", flexShrink: 0 }}>+</span> {s}
                    </div>
                  ))}
                </div>
                <div style={{ background: "rgba(255,107,107,0.07)", border: "1px solid rgba(255,107,107,0.2)", borderRadius: 14, padding: 20 }}>
                  <h3 style={{ fontSize: 14, fontWeight: 700, color: "#FF6B6B", textTransform: "uppercase", letterSpacing: "1px", marginBottom: 14 }}>🎯 Improve</h3>
                  {feedback.improvements.map((s, i) => (
                    <div key={i} style={{ fontSize: 13, color: "var(--text-primary)", marginBottom: 8, display: "flex", gap: 8 }}>
                      <span style={{ color: "#FF6B6B", flexShrink: 0 }}>→</span> {s}
                    </div>
                  ))}
                </div>
              </div>

              <div style={{ display: "flex", gap: 12, justifyContent: "center" }}>
                <motion.button whileHover={{ scale: 1.04 }} onClick={reset}
                  style={{ padding: "13px 32px", borderRadius: 12, background: "linear-gradient(135deg, #6C63FF, #4ECDC4)", border: "none", color: "white", fontWeight: 700, fontSize: 15, cursor: "pointer" }}>
                  🔄 Start New Interview
                </motion.button>
                <a href="/dashboard/certificates" style={{ textDecoration: "none" }}>
                  <button style={{ padding: "13px 28px", borderRadius: 12, background: "rgba(255,255,255,0.05)", border: "1px solid rgba(255,255,255,0.1)", color: "white", fontWeight: 600, fontSize: 14, cursor: "pointer" }}>
                    🎓 View Certificates
                  </button>
                </a>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useEffect } from "react";
import { useSelector } from "react-redux";
import { RootState } from "@/store";
import Sidebar from "@/components/dashboard/Sidebar";
import TopBar from "@/components/dashboard/TopBar";
import { motion, AnimatePresence } from "framer-motion";
import { BackgroundBeams } from "@/components/ui/BackgroundBeams";

export default function DashboardLayout({ children }: { children: React.ReactNode }) {
  const { data: session, status } = useSession();
  const router = useRouter();
  const sidebarOpen = useSelector((s: RootState) => s.ui.sidebarOpen);
  const user = session?.user as any;

  useEffect(() => {
    if (status === "unauthenticated") router.push("/auth");
    if (status === "authenticated" && user?.role === "admin") router.push("/admin");
  }, [status, user, router]);

  if (status === "loading") return (
    <div style={{ minHeight: "100vh", background: "var(--bg-primary)", display: "flex", alignItems: "center", justifyContent: "center", flexDirection: "column", gap: 16 }}>
      <motion.div
        animate={{ rotate: 360 }}
        transition={{ duration: 0.8, repeat: Infinity, ease: "linear" }}
        style={{ width: 48, height: 48, borderRadius: "50%", border: "3px solid rgba(124,58,237,0.2)", borderTopColor: "#7C3AED" } as any}
      />
      <p style={{ color: "var(--text-secondary)", fontSize: 14 }}>Loading your workspace...</p>
    </div>
  );

  if (!session) return null;

  return (
    <div style={{ display: "flex", minHeight: "100vh", background: "transparent" }}>
      <BackgroundBeams />
      <AnimatePresence>
        {sidebarOpen && (
          <motion.div
            initial={{ x: -280, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            exit={{ x: -280, opacity: 0 }}
            transition={{ duration: 0.22, ease: "easeOut" }}
            style={{ position: "fixed", left: 0, top: 0, bottom: 0, zIndex: 50 } as any}
          >
            <Sidebar />
          </motion.div>
        )}
      </AnimatePresence>

      <div style={{
        flex: 1,
        marginLeft: sidebarOpen ? 260 : 0,
        transition: "margin-left 0.22s ease",
        display: "flex",
        flexDirection: "column",
        minHeight: "100vh",
      }}>
        <TopBar />
        <main style={{ flex: 1, padding: "28px", overflowY: "auto" }}>
          <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.35 }}>
            {children}
          </motion.div>
        </main>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { motion } from "framer-motion";
import { useSession } from "next-auth/react";
import { activityApi } from "@/lib/api";

const RANK_COLORS = ["#FFD700", "#C0C0C0", "#CD7F32"];

export default function LeaderboardPage() {
  const { data: session } = useSession();
  const [leaderboard, setLeaderboard] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const currentUserId = (session?.user as { id?: number, email?: string, name?: string, accessToken?: string })?.id;
  const token = typeof window !== "undefined" ? localStorage.getItem("token") || "" : "";

  useEffect(() => {
    const fetchLeaderboard = async () => {
      try {
        const data = await activityApi.getLeaderboard(token);
        setLeaderboard(data.leaderboard || []);
      } catch (e) {}
      setLoading(false);
    };
    fetchLeaderboard();
  }, [token]);

  return (
    <div style={{ maxWidth: 800, margin: "0 auto", paddingBottom: 60 }}>
      
      {/* Header */}
      <div style={{ textAlign: "center", marginBottom: 40 }}>
        <motion.div
          initial={{ scale: 0, rotate: -10 }}
          animate={{ scale: 1, rotate: 0 }}
          transition={{ type: "spring", stiffness: 200, delay: 0.1 }}
          style={{ fontSize: 64, marginBottom: 16 }}>🏆</motion.div>
        <h1 style={{ fontSize: 36, fontWeight: 800, fontFamily: "var(--font-display)", marginBottom: 12 }}>
          Global <span className="gradient-text">Leaderboard</span>
        </h1>
        <p style={{ color: "var(--text-secondary)", fontSize: 16, maxWidth: 480, margin: "0 auto" }}>
          Top learners ranked by XP earned across all platform activities
        </p>
      </div>

      {/* Podium for Top 3 */}
      {!loading && leaderboard.length >= 3 && (
        <div style={{ display: "flex", alignItems: "flex-end", justifyContent: "center", gap: 16, marginBottom: 48, paddingBottom: 0 }}>
          {[leaderboard[1], leaderboard[0], leaderboard[2]].map((user, i) => {
            const rank = i === 1 ? 1 : i === 0 ? 2 : 3;
            const heights = [160, 200, 140];
            const colors = ["#C0C0C0", "#FFD700", "#CD7F32"];
            return (
              <motion.div
                key={user.id}
                initial={{ opacity: 0, y: 40 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.1 * rank }}
                style={{ display: "flex", flexDirection: "column", alignItems: "center", width: 160 }}>
                <div style={{ width: 52, height: 52, borderRadius: "50%", background: `linear-gradient(135deg, ${colors[i]}40, ${colors[i]}80)`, border: `2px solid ${colors[i]}`, display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 800, fontSize: 18, color: colors[i], marginBottom: 8, boxShadow: `0 0 20px ${colors[i]}40` }}>
                  {user.name.charAt(0).toUpperCase()}
                </div>
                <div style={{ fontSize: 14, fontWeight: 700, color: "white", marginBottom: 4 }}>{user.name}</div>
                <div style={{ fontSize: 13, color: colors[i], fontWeight: 700 }}>{user.xp} XP</div>
                <div style={{ marginTop: 12, width: "100%", height: heights[i], background: `linear-gradient(180deg, ${colors[i]}30 0%, ${colors[i]}10 100%)`, border: `1px solid ${colors[i]}40`, borderBottom: "none", borderRadius: "12px 12px 0 0", display: "flex", alignItems: "flex-start", justifyContent: "center", paddingTop: 16 }}>
                  <span style={{ fontSize: 28, fontWeight: 900, color: colors[i] }}>#{rank}</span>
                </div>
              </motion.div>
            );
          })}
        </div>
      )}

      {/* Full List */}
      <div className="dash-card" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{ padding: "18px 24px", borderBottom: "1px solid var(--border)" }}>
          <h2 style={{ fontSize: 17, fontWeight: 700, margin: 0 }}>All Rankings</h2>
        </div>

        {loading ? (
          <div style={{ padding: 40, textAlign: "center", color: "var(--text-muted)" }}>
            <div style={{ fontSize: 40, marginBottom: 16 }}>⏳</div>
            <div>Loading rankings...</div>
          </div>
        ) : leaderboard.length === 0 ? (
          <div style={{ padding: 40, textAlign: "center", color: "var(--text-muted)" }}>
            <div style={{ fontSize: 40, marginBottom: 16 }}>🏆</div>
            <div>No rankings yet. Start earning XP!</div>
          </div>
        ) : leaderboard.map((user, idx) => {
          const isCurrentUser = user.id === currentUserId;
          const isTop3 = idx < 3;
          return (
            <motion.div
              key={user.id}
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: idx * 0.04 }}
              style={{
                display: "flex", alignItems: "center", padding: "16px 24px", gap: 16,
                background: isCurrentUser ? "rgba(108,99,255,0.08)" : "transparent",
                borderLeft: isCurrentUser ? "3px solid var(--brand-primary)" : "3px solid transparent",
                borderBottom: idx < leaderboard.length - 1 ? "1px solid rgba(255,255,255,0.04)" : "none",
                transition: "background 0.2s",
              }}>
              {/* Rank */}
              <div style={{ width: 36, textAlign: "center", fontWeight: 900, fontSize: 18, color: isTop3 ? RANK_COLORS[idx] : "var(--text-muted)", flexShrink: 0 }}>
                {isTop3 ? ["🥇","🥈","🥉"][idx] : `#${idx + 1}`}
              </div>

              {/* Avatar */}
              {user.avatar ? (
                <img src={user.avatar} style={{ width: 42, height: 42, borderRadius: "50%" }} />
              ) : (
                <div style={{ width: 42, height: 42, borderRadius: "50%", background: isTop3 ? `linear-gradient(135deg, ${RANK_COLORS[idx]}, ${RANK_COLORS[idx]}80)` : "linear-gradient(135deg, #6C63FF, #3B82F6)", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 700, fontSize: 16, color: "white", flexShrink: 0 }}>
                  {user.name.charAt(0).toUpperCase()}
                </div>
              )}

              {/* Name + Level */}
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 700, fontSize: 15, color: isCurrentUser ? "white" : "var(--text-primary)", display: "flex", alignItems: "center", gap: 8 }}>
                  {user.name}
                  {isCurrentUser && <span style={{ fontSize: 11, background: "var(--brand-primary)", color: "white", padding: "2px 8px", borderRadius: 10, fontWeight: 600 }}>You</span>}
                </div>
                <div style={{ fontSize: 12, color: "var(--text-muted)", marginTop: 2 }}>Level {user.level}</div>
              </div>

              {/* XP */}
              <div style={{ textAlign: "right" }}>
                <div style={{ fontWeight: 800, fontSize: 17, color: isTop3 ? RANK_COLORS[idx] : "var(--brand-primary)" }}>
                  {(user.xp || 0).toLocaleString()} XP
                </div>
              </div>
            </motion.div>
          );
        })}
      </div>
    </div>
  );
}

