"use client";

import { useState, useEffect, useRef, useCallback } from "react";
import { websocketUrl } from "@/lib/api";

type WSStatus = "connecting" | "open" | "closed" | "error";

interface WSMessage {
  type: string;
  content?: string;
  role?: string;
  message?: string;
  timestamp?: number;
  [key: string]: unknown;
}

interface UseWebSocketOptions {
  /** JWT token for authentication */
  token: string;
  /** Chat room id */
  roomId?: string;
  /** Reconnect after this many ms (default: 3000) */
  reconnectDelay?: number;
  /** Maximum reconnect attempts (default: 10) */
  maxRetries?: number;
  /** Called on each incoming message */
  onMessage?: (msg: WSMessage) => void;
}

/**
 * Custom hook that wraps native WebSocket with:
 *  - Auto-reconnect with exponential backoff
 *  - Heartbeat pong response (every 30s server sends ping)
 *  - Stable sendMessage reference
 */
export function useWebSocket({
  token,
  roomId = "global",
  reconnectDelay = 3000,
  maxRetries = 10,
  onMessage,
}: UseWebSocketOptions) {
  const [status, setStatus] = useState<WSStatus>("closed");
  const [messages, setMessages] = useState<WSMessage[]>([]);

  const wsRef = useRef<WebSocket | null>(null);
  const retryCount = useRef(0);
  const reconnectTimeout = useRef<ReturnType<typeof setTimeout> | null>(null);
  const shouldClose = useRef(false);

  const buildUrl = useCallback((): string => {
    return `${websocketUrl("/ws/chat")}?token=${encodeURIComponent(token)}&room_id=${encodeURIComponent(roomId)}`;
  }, [token, roomId]);

  const connect = useCallback(() => {
    shouldClose.current = false;
    setStatus("connecting");

    const url = buildUrl();
    const ws = new WebSocket(url);
    wsRef.current = ws;

    ws.onopen = () => {
      setStatus("open");
      retryCount.current = 0;
    };

    ws.onmessage = (event) => {
      let data: WSMessage;
      try {
        data = JSON.parse(event.data);
      } catch {
        return;
      }

      // Respond to heartbeat pings
      if (data.type === "ping") {
        ws.send(JSON.stringify({ type: "pong" }));
        return;
      }

      setMessages((prev) => [...prev, data]);
      onMessage?.(data);
    };

    ws.onerror = () => {
      setStatus("error");
    };

    ws.onclose = () => {
      setStatus("closed");
      wsRef.current = null;

      if (shouldClose.current) return;

      if (retryCount.current < maxRetries) {
        retryCount.current += 1;
        // Exponential backoff: min 3s, max 30s
        const delay = Math.min(reconnectDelay * 2 ** (retryCount.current - 1), 30_000);
        console.warn(`WebSocket closed. Reconnecting in ${Math.round(delay / 1000)}s... (attempt ${retryCount.current}/${maxRetries})`);
        reconnectTimeout.current = setTimeout(connect, delay);
      } else {
        console.error("WebSocket max reconnect attempts reached.");
        setStatus("error");
      }
    };
  }, [token, roomId, buildUrl, reconnectDelay, maxRetries, onMessage]);

  useEffect(() => {
    connect();
    return () => {
      shouldClose.current = true;
      if (reconnectTimeout.current) clearTimeout(reconnectTimeout.current);
      wsRef.current?.close();
    };
  }, [connect]);

  const sendMessage = useCallback((content: string) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify({ type: "message", content }));
      // Optimistically add user message to local state
      setMessages((prev) => [
        ...prev,
        { type: "user_message", content, role: "user" },
      ]);
    } else {
      console.warn("WebSocket not open. Cannot send message.");
    }
  }, []);

  const clearMessages = useCallback(() => setMessages([]), []);

  return { status, messages, sendMessage, clearMessages, reconnect: connect };
}

"use client";

export const trackEvent = (eventName: string, params?: Record<string, any>) => {
  if (typeof window !== "undefined" && typeof (window as any).gtag === "function") {
    (window as any).gtag("event", eventName, params);
  } else if (process.env.NODE_ENV === "development") {
    console.log(`[Analytics Mock] Event: ${eventName}`, params);
  }
};

/**
 * Central API client for Tulasi AI backend.
 * Usage: import { api } from "@/lib/api"
 */

const isBrowser = typeof window !== "undefined";
const isDev = process.env.NODE_ENV === "development";
import toast from "react-hot-toast";

// ─── API Base URL ─────────────────────────────────────────────────────────────
// Env var is baked in at Vercel build time; fallback ensures local dev always works.
// We strip any trailing slashes or /api suffixes to prevent /api/api duplication.
export const API_URL = (process.env.NEXT_PUBLIC_API_URL || "https://tulasiai.up.railway.app")
  .replace(/\/api\/?$/, "")
  .replace(/\/$/, "");

/** Centralised debug logger — always prints in dev; silent in prod unless token missing */
function log(label: string, data?: unknown) {
  if (isDev) {
    console.log(`[TulasiAPI] ${label}`, data ?? "");
  }
}

/** Resolve token EXCLUSIVELY from localStorage */
function resolveToken(): string | undefined {
  if (isBrowser) {
    const stored = localStorage.getItem("token");
    if (stored) return stored;
  }
  return undefined;
}

/** Build a WebSocket URL pointing at the correct host (wss in production, ws locally) */
export function websocketUrl(path: string): string {
  if (!isBrowser) return "";
  const protocol = window.location.protocol === "https:" ? "wss:" : "ws:";
  const host = new URL(API_URL).host;
  return `${protocol}//${host}${path}`;
}

// ─── Helpers ────────────────────────────────────────────────────────────────

const FETCH_TIMEOUT_MS = 60_000; // 60s timeout for AI endpoints

async function fetchWithRetry(url: string, options: RequestInit, retries = 2): Promise<Response> {
  try {
    const controller = new AbortController();
    const id = setTimeout(() => controller.abort(), FETCH_TIMEOUT_MS);
    
    const res = await fetch(url, { ...options, signal: controller.signal });
    clearTimeout(id);

    if (!res.ok) {
      if (res.status === 502 || res.status === 503 || res.status === 504) {
         if (retries === 2) toast.loading("Server waking up. Retrying...", { id: "retry-toast" }); 
         throw new Error("API error / Server waking up");
      }
      if (res.status >= 500) {
         if (retries === 0) toast.error(`Server error: ${res.status}`);
         throw new Error(`API error: ${res.status}`);
      }
      return res; // return early for 4xx errors
    }
    toast.dismiss("retry-toast");
    return res;
  } catch (err: unknown) {
    const error = err as Error;
    if (retries === 0 || error.name === 'AbortError') {
      toast.dismiss("retry-toast");
      if (error.name === 'AbortError') {
        toast.error("Request timed out. Please try again.");
        throw new Error("Request timed out.");
      }
      toast.error("Connection failed. Check your network.");
      throw error;
    }
    // Exponential backoff for the 2 retries
    await new Promise(r => setTimeout(r, 1000 * (3 - retries)));
    return fetchWithRetry(url, options, retries - 1);
  }
}

async function request<T>(
  path: string,
  options: RequestInit = {},
  ignoredToken?: string
): Promise<T> {
  const token = resolveToken();
  const headers: Record<string, string> = {
    "Content-Type": "application/json",
    ...(options.headers as Record<string, string>),
  };
  if (token) {
    headers["Authorization"] = `Bearer ${token}`;
  }

  const fullUrl = `${API_URL}${path}`;

    try {
      const res = await fetchWithRetry(fullUrl, { ...options, headers, mode: "cors" });
      log(`← ${res.status} ${fullUrl}`);

    if (!res.ok) {
      if (res.status === 401) {
        if (isBrowser && !window.location.pathname.startsWith("/auth")) {
          window.location.href = "/auth";
        }
        throw new Error("Session expired. Please log in again.");
      }
      
      let backendMsg = res.statusText;
      try {
        const errJson = await res.json();
        backendMsg = errJson.detail || errJson.message || errJson.error || backendMsg;
      } catch (e) {}
      
      if (res.status >= 500) throw new Error(`500 Server Error: ${backendMsg}`);
      throw new Error(backendMsg || `Request failed: ${res.status}`);
    }
    const data = await res.json();
    
    // XP toast — clean, no emojis
    if (data && typeof data === "object" && typeof data.xp_earned === "number" && data.xp_earned > 0) {
      toast.success(`+${data.xp_earned} XP earned`, { 
        style: { borderRadius: "14px", background: "rgba(16,185,129,0.15)", border: "1px solid rgba(16,185,129,0.4)", color: "#10B981" } 
      });
    }
    
    return data;
  } catch (err: unknown) {
    const error = err as Error;
    const msg = error.message || "Network Error";
    if (msg.includes("Failed to fetch") || msg.includes("NetworkError") || msg.includes("ERR_NAME_NOT_RESOLVED")) {
      throw new Error("Backend unreachable. Check your connection.");
    }
    throw new Error(msg);
  }
}

// ─── Auth ────────────────────────────────────────────────────────────────────

export const authApi = {
  register: (email: string, password: string, name: string) =>
    request<{ access_token: string; user: User }>("/api/auth/register", {
      method: "POST",
      body: JSON.stringify({ email, password, name }),
    }),

  login: (email: string, password: string) =>
    request<{ access_token: string; user: User }>("/api/auth/login", {
      method: "POST",
      body: JSON.stringify({ email, password }),
    }),

  me: (token: string) =>
    request<User>("/api/auth/me", {}, token),
};

// ─── Chat ────────────────────────────────────────────────────────────────────

export const chatApi = {
  send: async (message: string, session_id?: string, tool?: string) => {
    let retries = 2;
    while (retries >= 0) {
      try {
        return await request<{ response: string; session_id?: string; model_used?: string }>(
          "/api/chat",
          { method: "POST", body: JSON.stringify({ message, session_id, tool }) }
        );
      } catch (err) {
        if (retries === 0) throw err;
        retries--;
        await new Promise(r => setTimeout(r, 2000)); // 2 sec delay
      }
    }
    throw new Error("Chat send failed after retries.");
  },

  feedback: (session_id: string, message_id: string, rating: number) =>
    request<{ status: string }>("/api/chat/feedback", {
      method: "POST",
      body: JSON.stringify({ session_id, message_id, rating }),
    }),

  history: (session_id: string) =>
    request<{ messages: ChatMsg[]; session_id: string }>(
      `/api/chat/history/${session_id}`,
      {}
    ),

  clearHistory: (session_id: string) =>
    request<{ message: string }>(`/api/chat/history/${session_id}`, { method: "DELETE" }),
};

// ─── PDF / RAG ───────────────────────────────────────────────────────────────

export const pdfApi = {
  upload: async (file: File, token: string) => {
    const form = new FormData();
    form.append("file", file);
    const res = await fetchWithRetry(`${API_URL}/api/pdf/upload`, {
      method: "POST",
      headers: { Authorization: `Bearer ${token}` },
      body: form,
    });
    if (!res.ok) throw new Error((await res.json()).detail || "Upload failed");
    return res.json() as Promise<{ session_id: string; pages: number; filename: string }>;
  },

  ask: (question: string, session_id: string, token: string) =>
    request<{ answer: string; source: string }>(
      "/api/pdf/ask",
      { method: "POST", body: JSON.stringify({ question, session_id }) },
      token
    ),
};

// ─── Roadmap ─────────────────────────────────────────────────────────────────

export const roadmapApi = {
  getRoadmaps: (token: string) => request<{ roadmaps: Roadmap[], completed_milestones: string[] }>("/api/roadmap/", {}, token),
  getRoadmap: (id: string, token: string) => request<Roadmap>(`/api/roadmap/${id}`, {}, token),
  logProgress: (roadmap_id: string, milestone_id: string, token: string) =>
    request<{ message: string; xp_earned: number }>("/api/roadmap/progress", {
